window.NECHTO_I18N = {"ru":{"title":"НЕЧТО","htmlTitle":"НЕЧТО — Протокол заражения","metaDesc":"Локальный цифровой симулятор настольной игры «Нечто» в стиле Jackbox. Хост на ТВ / Android TV / планшете — игроки подключаются с телефонов по QR-коду. 4–12 игроков, Wi-Fi, без регистрации.","heroRec":"REC · БОРТОВОЙ ЖУРНАЛ · СЕАНС ОТКРЫТ","heroTag":"Один экран на стене, телефоны — как пульты. <b>Найди заражённого</b>, пока корабль ещё дышит.","heroSub":"Локальный цифровой симулятор настольной игры в стиле Jackbox. Экипаж из восьми. Биосигнатур — восемь. Плюс ещё одна, которой не должно быть.","vPlayTV":"планшет / TV","vReg":"не нужна","ctaPlay":"Google Play · планшет / TV","ctaGameplay":"Геймплей","ctaDeck":"Колода","s1k":"// сигнал с борта","s1h":"Живая партия","s1sub":"Реальная партия за одним столом: ноутбук или Android-хост на общем экране — и телефоны игроков.","cap":"общий стол — то, что видят все. Секреты остаются в телефонах.","ytTag":"▶ ЗАПИСЬ ПАРТИИ · YOUTUBE","s2k":"// протокол хода","s2h":"Фазы хода","s2sub":"Каждый ход — три обязательных фазы. Пропустить нельзя ни одну — корабль не позволит.","p1n":"ФАЗА 1","p1h":"Тянет карту","p1p":"Берёшь верхнюю карту из колоды. Если попалась карта ПАНИКИ — она разыгрывается немедленно.","p2n":"ФАЗА 2","p2h":"Играет","p2p":"Разыгрываешь одну карту действия — или сбрасываешь. Защитные карты здесь не играются, они реакция.","p3n":"ФАЗА 3","p3h":"Обменивается","p3p":"Передаёшь карту соседу. Он отбивается защитой — или принимает. Что пришло в руку — остаётся. Навсегда.","shipNote":"<b>◆ Главное правило:</b> именно через обмен <b>Нечто</b> передаёт заражение. Каждый игрок становится соучастником, посредником или жертвой — иногда сам того не зная.","s3k":"// дистрибуция","s3h":"Скачать хост","s3sub":"Хост — это «стол». Игрокам ставить ничего не нужно: они заходят с телефона по QR-коду.","metaAndroid":"ПЛАНШЕТ / ANDROID TV","featBadge":"РЕКОМЕНДУЕМ","hostNote":"<b>Android — это хост</b>, а не клиент. Планшет или Android TV-приставка заменяют ноутбук: поднимают тот же Ktor-сервер и выводят общий стол на большой экран. Игроки по-прежнему подключаются с телефонов через браузер по QR-коду — ставить приложение им не нужно.","s4k":"// бортовой арсенал","s4h":"Колода","s4sub":"Три типа карт. Действия играются в свой ход, защита — реакция на чужой, паника тянется вместо обычной карты и срабатывает сразу.","tabAct":"Действия · 14","tabDef":"Защита · 5","tabPan":"Паника · 12","grpAct":"🟠 Действия — играются в фазе 2","grpDef":"🟢 Защита — реакция на чужой ход","grpPan":"🟣 Паника — срабатывает немедленно","tagAct":"действие","tagDefEx":"защита · обмен","tagDefMove":"защита · перемещение","tagDefFlame":"защита · огнемёт","tagPan":"паника","noteDef":"◆ Защита не разыгрывается в свой ход — только как реакция. Каждая карта защиты приносит <b>+1 карту</b> из колоды в качестве компенсации.","notePanic":"<b>⚠ Паника</b> тянется из отдельной колоды вместо обычной карты. Разыгрывается немедленно — нельзя сбросить, придержать или защититься заранее. Паника не слушается карантина. Паника не знает дверей.","s5k":"// инструктаж","s5h":"Как играть","step1":"Хост запускает приложение на <b>планшете, Android TV, ноутбуке или Steam Deck</b> — экран выводится на большой дисплей.","step2":"Игроки сканируют <b>QR-код</b> на экране со своих телефонов <i>(Chrome / Firefox)</i>. Установка не нужна.","step3":"Раздача, ходы, обмены — всё <b>с телефона</b>. Большой экран — общая память корабля, без секретов.","reqH":"Требования","reqHostH":"🖥️ Хост","reqHostP":"планшет / Android TV / любой ноутбук / Steam Deck с Wi-Fi","reqPlayersH":"📱 Игроки","reqPlayersP":"телефон с Chrome или Firefox (Safari не поддерживается)","reqNetH":"📡 Сеть","reqNetP":"общая Wi-Fi — корабль работает без выхода наружу","footQuote":"«Только не передавай мне ничего зелёного.»","lnkPrivacy":"Конфиденциальность","bStatus":"СТАТУС","bPlayers":"ИГРОКОВ","bNet":"СЕТЬ","bReg":"РЕГИСТРАЦИЯ","bLic":"ЛИЦЕНЗИЯ","sub":"ПРОТОКОЛ ЗАРАЖЕНИЯ","cards":{"MISS":{"n":"МИМО!","d":"Откажитесь от обмена картами. Вместо вас картами меняется следующий за вами игрок. Возьмите 1 карту события.","f":"— Не сегодня, дорогуша. Может, в другой раз."},"GET_OUT":{"n":"УБИРАЙСЯ ПРОЧЬ!","d":"Поменяйтесь местами с любым игроком по вашему выбору, если он не на карантине.","f":"Шлюз сработает через 3 секунды. На скафандр времени нет."},"BARRICADED_DOOR":{"n":"ЗАКОЛОЧЕННАЯ ДВЕРЬ","d":"Положите эту карту между собой и соседним игроком. Между вами не может совершаться никаких действий и обменов.","f":"Сварено, забито, окрашено. Кто-то очень не хотел, чтобы это вышло."},"ANALYSIS":{"n":"АНАЛИЗ","d":"Посмотрите все карты на руке выбранного соседнего игрока.","f":"…а теперь посмотрим, кто ты на самом деле."},"STAY_HERE":{"n":"МНЕ И ЗДЕСЬ НЕПЛОХО!","d":"Отмените эффект карты «Меняемся местами!» или «Сматывай удочки!», если стали её целью. Возьмите 1 карту события.","f":"У меня кресло. У меня лампа. У меня ствол на коленях. Я никуда."},"FORGETFULNESS":{"n":"ЗАБЫВЧИВОСТЬ","d":"Сбросьте 3 карты с руки и возьмите 3 новые карты событий. Сбрасывайте все попадающиеся карты паники.","f":"Кажется, я заходил сюда. Кажется, у меня было имя."},"NO_BBQ":{"n":"НИКАКОГО ШАШЛЫКА!","d":"Отмените эффект карты «Огнемёт», если стали её целью. Возьмите 1 карту события.","f":"Костюм держит до 1200°C. До этой штуки — секунд пять."},"NO_THANKS":{"n":"НЕТ УЖ, СПАСИБО!","d":"Откажитесь от обмена картами. Возьмите 1 карту события.","f":"Из стакана растёт лоза. Не пью."},"FEAR":{"n":"СТРАХ","d":"Откажитесь от обмена картами и посмотрите карту, от которой отказались. Возьмите 1 карту события.","f":"— Дайв! Открой шлюз! — …Дайв."},"CHAIN_REACTION":{"n":"ЦЕПНАЯ РЕАКЦИЯ","d":"Каждый игрок одновременно с остальными отдаёт 1 карту следующему по порядку хода игроку, игнорируя все сыгранные карты «Карантин» и «Заколоченная дверь». Ваш ход заканчивается.","f":"Сигнал прошёл по всей внутренней связи разом. Никто не может молчать."},"THREE_FOUR":{"n":"…ТРИ, ЧЕТЫРЕ…","d":"…открывайте дверь пошире! Все сыгранные карты «Заколоченная дверь» сбрасываются.","f":"Доски ломаются с третьего удара. Со второго — если бить чем-то, что больше не человек."},"ONE_TWO":{"n":"РАЗ, ДВА…","d":"…Нечто поднялось со дна! Поменяйтесь местами с третьим от вас игроком слева или справа (по вашему выбору). Игнорируйте все заколоченные двери.","f":"Под решёткой пола что-то есть. И сегодня оно решило, что устало быть под."},"JUST_BETWEEN_US":{"n":"ТОЛЬКО МЕЖДУ НАМИ…","d":"Покажите все карты на руке соседнему игроку по вашему выбору.","f":"Шифрованный канал. Гарантирует, что услышит только он. И тот, кто им стал."},"LETS_BE_FRIENDS":{"n":"ДАВАЙ ДРУЖИТЬ?","d":"Поменяйтесь 1 картой с любым игроком (по вашему выбору), если он не на карантине.","f":"Перчатка тёплая. Слишком тёплая. И что-то внутри неё двигается."},"CONFESSION_TIME":{"n":"ВРЕМЯ ПРИЗНАНИЙ","d":"Начиная с вас и по порядку хода, каждый игрок либо показывает, либо не показывает все карты на руке остальным игрокам.","f":"Под лампой каждый — подозреваемый. Даже свет."},"AXE":{"n":"ТОПОР","d":"Снимает «Карантин» с себя или соседнего игрока, или убирает «Заколоченную дверь» между вами.","f":"Стекло аварийного шкафа уже было разбито до меня."},"SWAP_PLACES":{"n":"МЕНЯЕМСЯ МЕСТАМИ!","d":"Поменяйтесь местами с соседним игроком, если он не на карантине. Игнорируйте все заколоченные двери.","f":"Коридор одинаков с обоих концов. Или нет?"},"QUARANTINE":{"n":"КАРАНТИН","d":"Сыграйте эту карту на себя или соседнего игрока. Следующие 3 своих хода игрок на карантине не может меняться картами, играть карты событий или становиться целью таких карт.","f":"Пристёгнут. Кричать в кляп бесполезно — никто не услышит."},"SUSPICION":{"n":"ПОДОЗРЕНИЕ","d":"Посмотрите 1 случайную карту на руке соседнего игрока.","f":"Когда мы садились — он был левшой. С тех пор он три раза взял кружку правой."},"REVERSE":{"n":"ЧТО-ТО ДВИЖЕТСЯ","d":"Меняет направление хода и обменов на противоположное.","f":"Дальше по коридору двигается. Не быстро. Но точно к нам."},"PERSISTENCE":{"n":"УПОРСТВО","d":"Возьмите 3 карты событий, оставьте на руке 1 и сбросьте остальные 2. Затем сыграйте или сбросьте 1 карту.","f":"Кровь не моя. Точнее, не вся."},"WHISKY":{"n":"ВИСКИ","d":"Покажите все свои карты остальным игрокам. Эту карту можно сыграть только на себя.","f":"В невесомости лёд не звенит. Зато стакан плывёт ровно туда, куда надо."},"RUN_AWAY":{"n":"СМАТЫВАЙ УДОЧКИ!","d":"Поменяйтесь местами с любым игроком по вашему выбору, если он не на карантине. Игнорируйте все заколоченные двери.","f":"До спасательной капсулы 90 метров. У него — 92."},"NECRONOMICON":{"n":"БОРТОВОЙ ЖУРНАЛ","d":"Сотрите любого игрока на ваш выбор.","f":"Запись 16: «Запускаю последовательность самоуничтожения. Любите свою кошку»."},"OOPS":{"n":"УУПС!","d":"Покажите все свои карты на руке остальным игрокам.","f":"Перчатка скользкая. Карты падают рубашкой вверх — но именно эта легла лицом."},"TEMPTATION":{"n":"СОБЛАЗН","d":"Поменяйтесь 1 картой с любым игроком по вашему выбору, если он не на карантине. Ваш ход заканчивается.","f":"Капсула манит. Кажется, она тёплая. Кажется, она дышит."},"FLAMETHROWER":{"n":"ОГНЕМЁТ","d":"Соседний игрок выбывает из игры.","f":"Клянусь, я сожгу любого, кто ко мне приблизится."},"BLIND_DATE":{"n":"СВИДАНИЕ ВСЛЕПУЮ","d":"Поменяйте 1 карту с руки на верхнюю карту общей колоды, сбрасывая все попадающиеся карты паники.","f":"Аппарат выдаёт случайную судьбу. Возврату не подлежит."},"OLD_ROPES":{"n":"СТАРЫЕ ВЕРЁВКИ","d":"Эти никчёмные верёвки рвутся от простого чиха! Все сыгранные карты «Карантин» сбрасываются.","f":"Связали на скорую руку. И на скорую руку же это закончилось."},"LOVECRAFT":{"n":"СТАРПОМ","d":"Посмотрите карты на руке любого выбранного игрока.","f":"Самый древний и сильный страх — страх неведомого. И вот мы стоим перед ним."},"WHAT_A_PARTY":{"n":"И ЭТО ВЫ НАЗЫВАЕТЕ ВЕЧЕРИНКОЙ?","d":"Все сыгранные карты «Карантин» и «Заколоченная дверь» сбрасываются. Затем, начиная с вас и по часовой стрелке, все игроки парами меняются местами.","f":"Стробоскоп бьёт. Кто-то танцует. Кто-то — почти."}}},"en":{"title":"THE THING","htmlTitle":"THE THING — Infection Protocol","metaDesc":"A local digital simulator of the board game in the Jackbox style. Host on a TV / Android TV / tablet — players join from their phones via a QR code. 4–12 players, Wi-Fi, no sign-up.","heroRec":"REC · SHIP'S LOG · SESSION OPEN","heroTag":"One screen on the wall, phones as controllers. <b>Find the infected one</b> while the ship still breathes.","heroSub":"A local digital simulator of a board game in the Jackbox style. A crew of eight. Eight biosignatures. Plus one more that shouldn't be there.","vPlayTV":"tablet / TV","vReg":"none","ctaPlay":"Google Play · tablet / TV","ctaGameplay":"Gameplay","ctaDeck":"The Deck","s1k":"// signal from the ship","s1h":"Live Game","s1sub":"A real game at one table: a laptop or Android host on the shared screen — and the players' phones.","cap":"the shared table — what everyone sees. Secrets stay on the phones.","ytTag":"▶ MATCH RECORDING · YOUTUBE","s2k":"// turn protocol","s2h":"Turn Phases","s2sub":"Every turn has three mandatory phases. You can't skip a single one — the ship won't allow it.","p1n":"PHASE 1","p1h":"Draws a card","p1p":"You take the top card from the deck. If it's a PANIC card — it plays immediately.","p2n":"PHASE 2","p2h":"Plays","p2p":"You play one action card — or discard. Defense cards aren't played here; they're a reaction.","p3n":"PHASE 3","p3h":"Exchanges","p3p":"You pass a card to your neighbor. They block it with defense — or accept it. Whatever lands in your hand stays. Forever.","shipNote":"<b>◆ The core rule:</b> it's through exchange that <b>The Thing</b> spreads the infection. Every player becomes an accomplice, a carrier or a victim — sometimes without knowing it.","s3k":"// distribution","s3h":"Download the host","s3sub":"The host is the \"table\". Players install nothing: they join from their phone via a QR code.","metaAndroid":"TABLET / ANDROID TV","featBadge":"RECOMMENDED","hostNote":"<b>Android is the host</b>, not the client. A tablet or Android TV box replaces the laptop: it runs the same Ktor server and shows the shared table on the big screen. Players still join from their phones via the browser and a QR code — they don't install anything.","s4k":"// onboard arsenal","s4h":"The Deck","s4sub":"Three card types. Actions are played on your turn, defense reacts to others, panic is drawn instead of a regular card and triggers at once.","tabAct":"Actions · 14","tabDef":"Defense · 5","tabPan":"Panic · 12","grpAct":"🟠 Actions — played in phase 2","grpDef":"🟢 Defense — a reaction to another's turn","grpPan":"🟣 Panic — triggers immediately","tagAct":"action","tagDefEx":"defense · exchange","tagDefMove":"defense · movement","tagDefFlame":"defense · flamethrower","tagPan":"panic","noteDef":"◆ Defense isn't played on your own turn — only as a reaction. Each defense card brings you <b>+1 card</b> from the deck as compensation.","notePanic":"<b>⚠ Panic</b> is drawn from a separate deck instead of a regular card. It plays immediately — you can't discard, hold or defend against it in advance. Panic ignores quarantine. Panic knows no doors.","s5k":"// briefing","s5h":"How to play","step1":"The host launches the app on a <b>tablet, Android TV, laptop or Steam Deck</b> — the screen goes to the big display.","step2":"Players scan the <b>QR code</b> on screen with their phones <i>(Chrome / Firefox)</i>. No install needed.","step3":"Dealing, turns, exchanges — all <b>from the phone</b>. The big screen is the ship's shared memory, no secrets.","reqH":"Requirements","reqHostH":"🖥️ Host","reqHostP":"tablet / Android TV / any laptop / Steam Deck with Wi-Fi","reqPlayersH":"📱 Players","reqPlayersP":"a phone with Chrome or Firefox (Safari not supported)","reqNetH":"📡 Network","reqNetP":"a shared Wi-Fi — the ship runs with no outside connection","footQuote":"\"Just don't pass me anything green.\"","lnkPrivacy":"Privacy","bStatus":"STATUS","bPlayers":"PLAYERS","bNet":"NETWORK","bReg":"SIGN-UP","bLic":"LICENSE","sub":"INFECTION PROTOCOL","cards":{"MISS":{"n":"MISS!","d":"Refuse a card exchange. Instead of you, the next player exchanges cards. Draw 1 action card.","f":"— Not today, sweetheart. Maybe another time."},"GET_OUT":{"n":"GET OUT!","d":"Swap places with any player of your choice, if they are not in quarantine.","f":"The airlock fires in 3 seconds. No time for a spacesuit."},"BARRICADED_DOOR":{"n":"BARRICADED DOOR","d":"Place this card between yourself and an adjacent player. No actions or exchanges can take place between you.","f":"Welded, nailed, painted. Someone really didn't want this to get out."},"ANALYSIS":{"n":"ANALYSIS","d":"Look at all cards in the hand of a chosen adjacent player.","f":"…now let's see who you really are."},"STAY_HERE":{"n":"I'M FINE HERE!","d":"Cancel the effect of Change Places! or Get Away From Here! if you were its target. Draw 1 action card.","f":"I have a chair. I have a lamp. I have a gun on my lap. I'm not going anywhere."},"FORGETFULNESS":{"n":"FORGETFULNESS","d":"Discard 3 cards from your hand and draw 3 new action cards. Discard any panic cards you encounter.","f":"I think I've been here before. I think I had a name."},"NO_BBQ":{"n":"NO BARBECUE!","d":"Cancel the effect of the Flamethrower card if you were its target. Draw 1 action card.","f":"The suit holds up to 1200°C. Against this thing — about five seconds."},"NO_THANKS":{"n":"NO, THANKS!","d":"Refuse a card exchange. Draw 1 action card.","f":"A vine is growing from the glass. Not drinking."},"FEAR":{"n":"FEAR","d":"Refuse a card exchange and look at the card you refused. Draw 1 action card.","f":"— Dave! Open the airlock! — …Dave."},"CHAIN_REACTION":{"n":"CHAIN REACTION","d":"Each player simultaneously passes 1 card to the next player in turn order, ignoring all played Quarantine and Barricaded Door cards. Your turn ends.","f":"The signal went through all internal comms at once. No one can stay silent."},"THREE_FOUR":{"n":"…THREE, FOUR…","d":"…open the door wide! All played Barricaded Door cards are discarded.","f":"Boards break on the third hit. On the second — if you're hitting with something that's no longer human."},"ONE_TWO":{"n":"ONE, TWO…","d":"…The Thing has risen from the deep! Swap places with the third player to your left or right (your choice). Ignore all Barricaded Doors.","f":"Something is under the floor grating. And today it decided it was tired of being underneath."},"JUST_BETWEEN_US":{"n":"JUST BETWEEN US…","d":"Show all your hand cards to an adjacent player of your choice.","f":"Encrypted channel. Guarantees only he'll hear. And whoever he's become."},"LETS_BE_FRIENDS":{"n":"LET'S BE FRIENDS!","d":"Exchange 1 card with any player (your choice), if they are not in quarantine.","f":"The glove is warm. Too warm. And something inside it is moving."},"CONFESSION_TIME":{"n":"CONFESSION TIME","d":"Starting with you and in turn order, each player either shows or doesn't show all their cards to the other players.","f":"Under the lamp, everyone is a suspect. Even the light."},"AXE":{"n":"AXE","d":"Remove Quarantine from yourself or an adjacent player, or remove a Barricaded Door between you.","f":"The emergency cabinet glass was already broken when I got here."},"SWAP_PLACES":{"n":"CHANGE PLACES!","d":"Swap places with an adjacent player, if they are not in quarantine. Ignore all Barricaded Doors.","f":"The corridor looks the same from both ends. Or does it?"},"QUARANTINE":{"n":"QUARANTINE","d":"Play on yourself or an adjacent player. For their next 3 turns, the quarantined player cannot exchange cards, play action cards, or be the target of such cards.","f":"Strapped in. Screaming into the gag is pointless — no one will hear."},"SUSPICION":{"n":"SUSPICION","d":"Look at 1 random card in the hand of an adjacent player.","f":"When we sat down — he was left-handed. Since then he's picked up his mug with his right hand three times."},"REVERSE":{"n":"SOMETHING IS MOVING","d":"Changes the direction of turns and exchanges to the opposite.","f":"Something is moving further down the corridor. Slowly. But definitely toward us."},"PERSISTENCE":{"n":"PERSISTENCE","d":"Draw 3 action cards, keep 1 in hand and discard the other 2. Then play or discard 1 card.","f":"The blood isn't mine. Well, not all of it."},"WHISKY":{"n":"WHISKY","d":"Show all your cards to the other players. This card can only be played on yourself.","f":"In zero gravity ice doesn't clink. But the glass drifts exactly where it needs to go."},"RUN_AWAY":{"n":"GET AWAY FROM HERE!","d":"Swap places with any player of your choice, if they are not in quarantine. Ignore all Barricaded Doors.","f":"90 meters to the escape pod. He has 92."},"NECRONOMICON":{"n":"SHIP'S LOG","d":"Eliminate any player of your choice.","f":"Log 16: \"Initiating self-destruct sequence. Love your cat.\""},"OOPS":{"n":"OOPS!","d":"Show all your hand cards to the other players.","f":"The glove is slippery. Cards fall face down — but this one landed face up."},"TEMPTATION":{"n":"TEMPTATION","d":"Exchange 1 card with any player of your choice, if they are not in quarantine. Your turn ends.","f":"The capsule beckons. It seems warm. It seems to breathe."},"FLAMETHROWER":{"n":"FLAMETHROWER","d":"An adjacent player is eliminated from the game.","f":"I swear I'll burn anyone who comes near me."},"BLIND_DATE":{"n":"BLIND DATE","d":"Swap 1 card from your hand with the top card of the deck, discarding any panic cards encountered.","f":"The machine dispenses a random fate. Non-refundable."},"OLD_ROPES":{"n":"OLD ROPES","d":"These useless ropes snap at the slightest touch! All played Quarantine cards are discarded.","f":"Tied in a hurry. And ended just as quickly."},"LOVECRAFT":{"n":"FIRST MATE","d":"Look at the cards in the hand of any chosen player.","f":"The oldest and strongest fear is fear of the unknown. And here we stand before it."},"WHAT_A_PARTY":{"n":"WHAT A PARTY!","d":"All played Quarantine and Barricaded Door cards are discarded. Then, starting with you clockwise, all players swap places in pairs.","f":"The strobe is flashing. Someone's dancing. Someone's almost dancing."}}},"es":{"title":"LA COSA","htmlTitle":"LA COSA — Protocolo de Infección","metaDesc":"Simulador digital local del juego de mesa al estilo Jackbox. El anfitrión va en TV / Android TV / tablet; los jugadores se unen desde el móvil con un código QR. 4–12 jugadores, Wi-Fi, sin registro.","heroRec":"REC · DIARIO DE A BORDO · SESIÓN ABIERTA","heroTag":"Una pantalla en la pared, los móviles como mandos. <b>Encuentra al infectado</b> mientras la nave aún respira.","heroSub":"Simulador digital local de un juego de mesa al estilo Jackbox. Una tripulación de ocho. Ocho biofirmas. Y una más que no debería estar ahí.","vPlayTV":"tablet / TV","vReg":"no hace falta","ctaPlay":"Google Play · tablet / TV","ctaGameplay":"Gameplay","ctaDeck":"La baraja","s1k":"// señal desde la nave","s1h":"Partida en vivo","s1sub":"Una partida real en una mesa: un portátil o un host Android en la pantalla común — y los móviles de los jugadores.","cap":"la mesa común — lo que ven todos. Los secretos quedan en los móviles.","ytTag":"▶ GRABACIÓN DE PARTIDA · YOUTUBE","s2k":"// protocolo del turno","s2h":"Fases del turno","s2sub":"Cada turno tiene tres fases obligatorias. No puedes saltarte ninguna — la nave no lo permite.","p1n":"FASE 1","p1h":"Roba carta","p1p":"Tomas la carta superior del mazo. Si es una carta de PÁNICO, se juega de inmediato.","p2n":"FASE 2","p2h":"Juega","p2p":"Juegas una carta de acción — o descartas. Las cartas de defensa no se juegan aquí; son una reacción.","p3n":"FASE 3","p3h":"Intercambia","p3p":"Pasas una carta a tu vecino. Él la rechaza con defensa — o la acepta. Lo que llega a tu mano se queda. Para siempre.","shipNote":"<b>◆ La regla clave:</b> es a través del intercambio como <b>La Cosa</b> propaga la infección. Cada jugador se vuelve cómplice, portador o víctima — a veces sin saberlo.","s3k":"// distribución","s3h":"Descargar el host","s3sub":"El host es la \"mesa\". Los jugadores no instalan nada: entran desde el móvil con un código QR.","metaAndroid":"TABLET / ANDROID TV","featBadge":"RECOMENDADO","hostNote":"<b>Android es el host</b>, no el cliente. Una tablet o un dispositivo Android TV sustituyen al portátil: levantan el mismo servidor Ktor y muestran la mesa común en la pantalla grande. Los jugadores siguen entrando desde el móvil con el navegador y un código QR — no instalan nada.","s4k":"// arsenal de a bordo","s4h":"La baraja","s4sub":"Tres tipos de carta. Las acciones se juegan en tu turno, la defensa reacciona al de otros, el pánico se roba en lugar de una carta normal y se activa al instante.","tabAct":"Acciones · 14","tabDef":"Defensa · 5","tabPan":"Pánico · 12","grpAct":"🟠 Acciones — se juegan en la fase 2","grpDef":"🟢 Defensa — reacción al turno ajeno","grpPan":"🟣 Pánico — se activa de inmediato","tagAct":"acción","tagDefEx":"defensa · intercambio","tagDefMove":"defensa · movimiento","tagDefFlame":"defensa · lanzallamas","tagPan":"pánico","noteDef":"◆ La defensa no se juega en tu turno — solo como reacción. Cada carta de defensa te da <b>+1 carta</b> del mazo como compensación.","notePanic":"<b>⚠ El pánico</b> se roba de un mazo aparte en lugar de una carta normal. Se juega de inmediato — no puedes descartarlo, guardarlo ni defenderte por adelantado. El pánico ignora la cuarentena. El pánico no conoce puertas.","s5k":"// instrucciones","s5h":"Cómo jugar","step1":"El anfitrión abre la app en una <b>tablet, Android TV, portátil o Steam Deck</b> — la pantalla va al monitor grande.","step2":"Los jugadores escanean el <b>código QR</b> en pantalla con sus móviles <i>(Chrome / Firefox)</i>. Sin instalar nada.","step3":"Reparto, turnos, intercambios — todo <b>desde el móvil</b>. La pantalla grande es la memoria común de la nave, sin secretos.","reqH":"Requisitos","reqHostH":"🖥️ Host","reqHostP":"tablet / Android TV / cualquier portátil / Steam Deck con Wi-Fi","reqPlayersH":"📱 Jugadores","reqPlayersP":"un móvil con Chrome o Firefox (Safari no compatible)","reqNetH":"📡 Red","reqNetP":"una Wi-Fi común — la nave funciona sin conexión al exterior","footQuote":"«Solo no me pases nada verde.»","lnkPrivacy":"Privacidad","bStatus":"ESTADO","bPlayers":"JUGADORES","bNet":"RED","bReg":"REGISTRO","bLic":"LICENCIA","sub":"PROTOCOLO DE INFECCIÓN","cards":{"MISS":{"n":"¡ESQUIVADO!","d":"Rechaza un intercambio de cartas. En tu lugar, el siguiente jugador intercambia cartas. Roba 1 carta de acción.","f":"— Hoy no, cariño. Quizás otra vez."},"GET_OUT":{"n":"¡FUERA DE AQUÍ!","d":"Cámbiante de lugar con cualquier jugador elegido, si no está en cuarentena.","f":"La esclusa se activa en 3 segundos. No hay tiempo para el traje."},"BARRICADED_DOOR":{"n":"PUERTA ATRANCADA","d":"Coloca esta carta entre tú y un jugador adyacente. Entre vosotros no pueden realizarse acciones ni intercambios.","f":"Soldado, clavado, pintado. Alguien no quería que esto saliera."},"ANALYSIS":{"n":"ANÁLISIS","d":"Mira todas las cartas en la mano de un jugador adyacente elegido.","f":"…ahora veamos quién eres realmente."},"STAY_HERE":{"n":"¡AQUÍ ME QUEDO!","d":"Cancela el efecto de ¡Cambia de Lugar! o ¡Corre! si fuiste su objetivo. Roba 1 carta de acción.","f":"Tengo una silla. Tengo una lámpara. Tengo un arma en el regazo. No voy a ningún lado."},"FORGETFULNESS":{"n":"OLVIDO","d":"Descarta 3 cartas de tu mano y roba 3 nuevas cartas de acción. Descarta las cartas de pánico que encuentres.","f":"Creo que he estado aquí antes. Creo que tenía un nombre."},"NO_BBQ":{"n":"¡NADA DE BARBACOA!","d":"Cancela el efecto del Lanzallamas si fuiste su objetivo. Roba 1 carta de acción.","f":"El traje aguanta hasta 1200°C. Con esta cosa — unos cinco segundos."},"NO_THANKS":{"n":"¡NO, GRACIAS!","d":"Rechaza un intercambio de cartas. Roba 1 carta de acción.","f":"Una enredadera crece desde el vaso. No bebo."},"FEAR":{"n":"MIEDO","d":"Rechaza un intercambio de cartas y mira la carta rechazada. Roba 1 carta de acción.","f":"— ¡Dave! ¡Abre la esclusa! — …Dave."},"CHAIN_REACTION":{"n":"REACCIÓN EN CADENA","d":"Cada jugador pasa simultáneamente 1 carta al siguiente jugador en orden de turno, ignorando todas las cartas de Cuarentena y Puerta Atrancada. Tu turno termina.","f":"La señal recorrió todas las comunicaciones internas a la vez. Nadie puede guardar silencio."},"THREE_FOUR":{"n":"…TRES, CUATRO…","d":"…¡abre bien la puerta! Todas las cartas de Puerta Atrancada jugadas son descartadas.","f":"Las tablas se rompen al tercer golpe. Al segundo — si golpeas con algo que ya no es humano."},"ONE_TWO":{"n":"UNO, DOS…","d":"…¡La Cosa ha emergido de las profundidades! Cámbiante de lugar con el tercer jugador a tu izquierda o derecha (tu elección). Ignora todas las Puertas Atrancadas.","f":"Hay algo bajo la rejilla del suelo. Y hoy decidió que estaba cansado de estar debajo."},"JUST_BETWEEN_US":{"n":"SOLO ENTRE NOSOTROS…","d":"Muestra todas tus cartas de mano a un jugador adyacente de tu elección.","f":"Canal cifrado. Garantiza que solo él escuchará. Y quien se haya convertido en él."},"LETS_BE_FRIENDS":{"n":"¿SEAMOS AMIGOS?","d":"Intercambia 1 carta con cualquier jugador (tu elección), si no está en cuarentena.","f":"El guante está cálido. Demasiado cálido. Y algo dentro se mueve."},"CONFESSION_TIME":{"n":"HORA DE CONFESIONES","d":"Empezando por ti y en orden de turno, cada jugador elige mostrar o no mostrar todas sus cartas a los demás.","f":"Bajo la lámpara, todos son sospechosos. Incluso la luz."},"AXE":{"n":"HACHA","d":"Elimina la Cuarentena de ti mismo o de un jugador adyacente, o elimina una Puerta Atrancada entre vosotros.","f":"El cristal del armario de emergencias ya estaba roto cuando llegué."},"SWAP_PLACES":{"n":"¡CAMBIA DE LUGAR!","d":"Cámbiante de lugar con un jugador adyacente, si no está en cuarentena. Ignora todas las Puertas Atrancadas.","f":"El pasillo se ve igual desde ambos extremos. ¿O no?"},"QUARANTINE":{"n":"CUARENTENA","d":"Juégala sobre ti mismo o un jugador adyacente. Durante sus próximos 3 turnos, el jugador en cuarentena no puede intercambiar cartas, jugar cartas de acción ni ser objetivo de tales cartas.","f":"Atado. Gritar con una mordaza es inútil — nadie escuchará."},"SUSPICION":{"n":"SOSPECHA","d":"Mira 1 carta al azar en la mano de un jugador adyacente.","f":"Cuando nos sentamos — era zurdo. Desde entonces ha cogido la taza con la derecha tres veces."},"REVERSE":{"n":"ALGO SE MUEVE","d":"Cambia la dirección de los turnos e intercambios a la contraria.","f":"Algo se mueve más adelante en el pasillo. Lento. Pero definitivamente hacia nosotros."},"PERSISTENCE":{"n":"PERSEVERANCIA","d":"Roba 3 cartas de acción, guarda 1 en la mano y descarta las otras 2. Luego juega o descarta 1 carta.","f":"La sangre no es mía. Bueno, no toda."},"WHISKY":{"n":"WHISKY","d":"Muestra todas tus cartas a los demás jugadores. Esta carta solo puede jugarse sobre ti mismo.","f":"En ingravidez el hielo no tintinea. Pero el vaso flota exactamente hacia donde necesita ir."},"RUN_AWAY":{"n":"¡CORRE!","d":"Cámbiante de lugar con cualquier jugador elegido, si no está en cuarentena. Ignora todas las Puertas Atrancadas.","f":"90 metros hasta la cápsula de escape. Él tiene 92."},"NECRONOMICON":{"n":"DIARIO DE ABORDO","d":"Elimina a cualquier jugador de tu elección.","f":"Registro 16: «Iniciando secuencia de autodestrucción. Quiere a tu gato.»"},"OOPS":{"n":"¡UPS!","d":"Muestra todas tus cartas de mano a los demás jugadores.","f":"El guante es resbaladizo. Las cartas caen boca abajo — pero esta quedó boca arriba."},"TEMPTATION":{"n":"TENTACIÓN","d":"Intercambia 1 carta con cualquier jugador elegido, si no está en cuarentena. Tu turno termina.","f":"La cápsula llama. Parece cálida. Parece respirar."},"FLAMETHROWER":{"n":"LANZALLAMAS","d":"Un jugador adyacente es eliminado de la partida.","f":"Juro que quemaré a cualquiera que se acerque."},"BLIND_DATE":{"n":"CITA A CIEGAS","d":"Intercambia 1 carta de tu mano con la carta superior del mazo, descartando las cartas de pánico que encuentres.","f":"La máquina dispensa un destino aleatorio. Sin devolución."},"OLD_ROPES":{"n":"CUERDAS VIEJAS","d":"¡Estas cuerdas inútiles se rompen con un soplo! Todas las cartas de Cuarentena jugadas son descartadas.","f":"Atadas con prisa. Y terminaron igual de rápido."},"LOVECRAFT":{"n":"PRIMER OFICIAL","d":"Mira las cartas en la mano de cualquier jugador elegido.","f":"El miedo más antiguo y poderoso es el miedo a lo desconocido. Y aquí estamos ante él."},"WHAT_A_PARTY":{"n":"¿A ESTO LE LLAMAS FIESTA?","d":"Todas las cartas de Cuarentena y Puerta Atrancada jugadas son descartadas. Luego, empezando por ti en sentido horario, todos los jugadores intercambian lugares por parejas.","f":"El estroboscopio parpadea. Alguien baila. Alguien casi baila."}}},"de":{"title":"DAS DING","htmlTitle":"DAS DING — Infektionsprotokoll","metaDesc":"Lokaler digitaler Simulator des Brettspiels im Jackbox-Stil. Host auf TV / Android TV / Tablet — Spieler treten per QR-Code vom Handy bei. 4–12 Spieler, WLAN, ohne Anmeldung.","heroRec":"REC · BORDBUCH · SITZUNG OFFEN","heroTag":"Ein Bildschirm an der Wand, Handys als Controller. <b>Finde den Infizierten</b>, solange das Schiff noch atmet.","heroSub":"Lokaler digitaler Simulator eines Brettspiels im Jackbox-Stil. Eine Crew aus acht. Acht Biosignaturen. Plus eine weitere, die nicht da sein dürfte.","vPlayTV":"Tablet / TV","vReg":"nicht nötig","ctaPlay":"Google Play · Tablet / TV","ctaGameplay":"Gameplay","ctaDeck":"Das Deck","s1k":"// Signal vom Schiff","s1h":"Live-Partie","s1sub":"Eine echte Partie an einem Tisch: ein Laptop oder Android-Host auf dem gemeinsamen Bildschirm — und die Handys der Spieler.","cap":"der gemeinsame Tisch — was alle sehen. Geheimnisse bleiben auf den Handys.","ytTag":"▶ PARTIE-AUFNAHME · YOUTUBE","s2k":"// Zug-Protokoll","s2h":"Zugphasen","s2sub":"Jeder Zug hat drei Pflichtphasen. Keine darf übersprungen werden — das Schiff lässt es nicht zu.","p1n":"PHASE 1","p1h":"Zieht eine Karte","p1p":"Du nimmst die oberste Karte vom Stapel. Ist es eine PANIK-Karte, wird sie sofort ausgespielt.","p2n":"PHASE 2","p2h":"Spielt","p2p":"Du spielst eine Aktionskarte — oder legst ab. Verteidigungskarten werden hier nicht gespielt; sie sind eine Reaktion.","p3n":"PHASE 3","p3h":"Tauscht","p3p":"Du gibst dem Nachbarn eine Karte. Er wehrt mit Verteidigung ab — oder nimmt sie an. Was in deine Hand kommt, bleibt. Für immer.","shipNote":"<b>◆ Die Grundregel:</b> gerade über den Tausch verbreitet <b>Das Ding</b> die Infektion. Jeder Spieler wird zum Komplizen, Überträger oder Opfer — manchmal ohne es zu wissen.","s3k":"// Vertrieb","s3h":"Host herunterladen","s3sub":"Der Host ist der \"Tisch\". Spieler installieren nichts: Sie treten per QR-Code vom Handy bei.","metaAndroid":"TABLET / ANDROID TV","featBadge":"EMPFOHLEN","hostNote":"<b>Android ist der Host</b>, nicht der Client. Ein Tablet oder eine Android-TV-Box ersetzt den Laptop: Sie startet denselben Ktor-Server und zeigt den gemeinsamen Tisch auf dem großen Bildschirm. Spieler treten weiterhin per Browser und QR-Code vom Handy bei — sie installieren nichts.","s4k":"// Bord-Arsenal","s4h":"Das Deck","s4sub":"Drei Kartentypen. Aktionen werden im eigenen Zug gespielt, Verteidigung reagiert auf andere, Panik wird statt einer normalen Karte gezogen und löst sofort aus.","tabAct":"Aktionen · 14","tabDef":"Verteidigung · 5","tabPan":"Panik · 12","grpAct":"🟠 Aktionen — werden in Phase 2 gespielt","grpDef":"🟢 Verteidigung — Reaktion auf fremde Züge","grpPan":"🟣 Panik — löst sofort aus","tagAct":"Aktion","tagDefEx":"Verteidigung · Tausch","tagDefMove":"Verteidigung · Bewegung","tagDefFlame":"Verteidigung · Flammenwerfer","tagPan":"Panik","noteDef":"◆ Verteidigung wird nicht im eigenen Zug gespielt — nur als Reaktion. Jede Verteidigungskarte bringt dir <b>+1 Karte</b> vom Stapel als Ausgleich.","notePanic":"<b>⚠ Panik</b> wird aus einem separaten Stapel statt einer normalen Karte gezogen. Sie wird sofort gespielt — nicht ablegbar, nicht aufhebbar, nicht im Voraus abwehrbar. Panik ignoriert Quarantäne. Panik kennt keine Türen.","s5k":"// Einweisung","s5h":"So wird gespielt","step1":"Der Host startet die App auf einem <b>Tablet, Android TV, Laptop oder Steam Deck</b> — das Bild geht auf den großen Schirm.","step2":"Die Spieler scannen den <b>QR-Code</b> am Bildschirm mit dem Handy <i>(Chrome / Firefox)</i>. Keine Installation nötig.","step3":"Austeilen, Züge, Tausch — alles <b>vom Handy</b>. Der große Schirm ist das gemeinsame Gedächtnis des Schiffs, ohne Geheimnisse.","reqH":"Voraussetzungen","reqHostH":"🖥️ Host","reqHostP":"Tablet / Android TV / beliebiger Laptop / Steam Deck mit WLAN","reqPlayersH":"📱 Spieler","reqPlayersP":"ein Handy mit Chrome oder Firefox (Safari nicht unterstützt)","reqNetH":"📡 Netzwerk","reqNetP":"ein gemeinsames WLAN — das Schiff läuft ohne Verbindung nach außen","footQuote":"„Reich mir nur nichts Grünes.“","lnkPrivacy":"Datenschutz","bStatus":"STATUS","bPlayers":"SPIELER","bNet":"NETZWERK","bReg":"ANMELDUNG","bLic":"LIZENZ","sub":"INFEKTIONSPROTOKOLL","cards":{"MISS":{"n":"VERFEHLT!","d":"Verweigere einen Kartentausch. Statt dir tauscht der nächste Spieler. Ziehe 1 Aktionskarte.","f":"— Heute nicht, Schatz. Vielleicht ein anderes Mal."},"GET_OUT":{"n":"RAUS HIER!","d":"Tausche den Platz mit einem beliebigen Spieler deiner Wahl, wenn er nicht in Quarantäne ist.","f":"Die Luftschleuse wird in 3 Sekunden ausgelöst. Keine Zeit für den Anzug."},"BARRICADED_DOOR":{"n":"VERBARRIKADIERTE TÜR","d":"Lege diese Karte zwischen dich und einen benachbarten Spieler. Zwischen euch können keine Aktionen oder Tausche stattfinden.","f":"Geschweißt, vernagelt, gestrichen. Jemand wollte unbedingt verhindern, dass es herauskommt."},"ANALYSIS":{"n":"ANALYSE","d":"Sieh alle Karten in der Hand eines gewählten benachbarten Spielers.","f":"…jetzt sehen wir mal, wer du wirklich bist."},"STAY_HERE":{"n":"ICH BLEIB HIER!","d":"Brich den Effekt von Plätze Tauschen! oder Lauf! ab, wenn du ihr Ziel warst. Ziehe 1 Aktionskarte.","f":"Ich habe einen Stuhl. Ich habe eine Lampe. Ich habe eine Waffe auf dem Schoß. Ich gehe nirgendwo hin."},"FORGETFULNESS":{"n":"VERGESSLICHKEIT","d":"Lege 3 Karten aus deiner Hand ab und ziehe 3 neue Aktionskarten. Lege dabei Panikkarten ab.","f":"Ich glaube, ich war schon hier. Ich glaube, ich hatte einen Namen."},"NO_BBQ":{"n":"KEIN GRILLABEND!","d":"Brich den Effekt des Flammenwerfers ab, wenn du sein Ziel warst. Ziehe 1 Aktionskarte.","f":"Der Anzug hält bis 1200°C stand. Gegen dieses Ding — ungefähr fünf Sekunden."},"NO_THANKS":{"n":"NEIN DANKE!","d":"Verweigere einen Kartentausch. Ziehe 1 Aktionskarte.","f":"Im Glas wächst eine Ranke. Ich trinke nicht."},"FEAR":{"n":"ANGST","d":"Verweigere einen Kartentausch und sieh die verweigerte Karte. Ziehe 1 Aktionskarte.","f":"— Dave! Öffne die Luftschleuse! — …Dave."},"CHAIN_REACTION":{"n":"KETTENREAKTION","d":"Jeder Spieler gibt gleichzeitig 1 Karte an den nächsten in der Zugreihenfolge weiter, und ignoriert dabei alle Quarantäne- und Verbarrikadierte-Tür-Karten. Dein Zug endet.","f":"Das Signal durchlief alle internen Kommunikationen gleichzeitig. Niemand kann schweigen."},"THREE_FOUR":{"n":"…DREI, VIER…","d":"…Tür weit aufmachen! Alle gespielten Karten Verbarrikadierte Tür werden abgelegt.","f":"Bretter brechen beim dritten Schlag. Beim zweiten — wenn man mit etwas schlägt, das kein Mensch mehr ist."},"ONE_TWO":{"n":"EINS, ZWEI…","d":"…Das Ding ist aus der Tiefe aufgestiegen! Tausche den Platz mit dem dritten Spieler links oder rechts von dir (deine Wahl). Ignoriere alle Verbarrikadierten Türen.","f":"Unter dem Bodengitter ist etwas. Und heute hat es beschlossen, dass es das Untersein satt hat."},"JUST_BETWEEN_US":{"n":"NUR ZWISCHEN UNS…","d":"Zeige allen deine Handkarten einem benachbarten Spieler deiner Wahl.","f":"Verschlüsselter Kanal. Garantiert, dass nur er es hört. Und das, was er geworden ist."},"LETS_BE_FRIENDS":{"n":"WOLLEN WIR FREUNDE SEIN?","d":"Tausche 1 Karte mit einem beliebigen Spieler (deine Wahl), wenn er nicht in Quarantäne ist.","f":"Der Handschuh ist warm. Zu warm. Und drinnen bewegt sich etwas."},"CONFESSION_TIME":{"n":"GESTÄNDNISZEIT","d":"Beginnend mit dir und in Zugreihenfolge, zeigt jeder Spieler entweder alle Karten oder verbirgt sie vor den anderen.","f":"Unter der Lampe ist jeder verdächtig. Selbst das Licht."},"AXE":{"n":"AXT","d":"Hebt die Quarantäne von dir selbst oder einem benachbarten Spieler auf, oder entfernt eine Verbarrikadierte Tür zwischen euch.","f":"Das Glas des Notfallschranks war bereits eingeschlagen, als ich ankam."},"SWAP_PLACES":{"n":"PLÄTZE TAUSCHEN!","d":"Tausche den Platz mit einem benachbarten Spieler, wenn er nicht in Quarantäne ist. Ignoriere alle Verbarrikadierten Türen.","f":"Der Korridor sieht von beiden Enden gleich aus. Oder doch nicht?"},"QUARANTINE":{"n":"QUARANTÄNE","d":"Spiele auf dich selbst oder einen benachbarten Spieler. Für die nächsten 3 eigenen Züge kann der unter Quarantäne stehende Spieler keine Karten tauschen, keine Aktionskarten spielen und auch nicht Ziel solcher Karten werden.","f":"Festgeschnallt. In den Knebel zu schreien ist sinnlos — niemand hört es."},"SUSPICION":{"n":"VERDACHT","d":"Sieh 1 zufällige Karte in der Hand eines benachbarten Spielers.","f":"Als wir uns setzten — war er Linkshänder. Seitdem hat er die Tasse dreimal mit rechts gehoben."},"REVERSE":{"n":"ETWAS BEWEGT SICH","d":"Ändert die Richtung der Züge und Tausche ins Gegenteil.","f":"Weiter hinten im Korridor bewegt sich etwas. Langsam. Aber eindeutig auf uns zu."},"PERSISTENCE":{"n":"HARTNÄCKIGKEIT","d":"Ziehe 3 Aktionskarten, behalte 1 auf der Hand und lege die anderen 2 ab. Dann spiele oder lege 1 Karte ab.","f":"Das Blut ist nicht meins. Naja, nicht alles."},"WHISKY":{"n":"WHISKY","d":"Zeige allen anderen Spielern deine gesamte Hand. Diese Karte kann nur auf dich selbst gespielt werden.","f":"In der Schwerelosigkeit klingt das Eis nicht. Aber das Glas treibt genau dorthin, wohin es muss."},"RUN_AWAY":{"n":"LAUF!","d":"Tausche den Platz mit einem beliebigen Spieler deiner Wahl, wenn er nicht in Quarantäne ist. Ignoriere alle Verbarrikadierten Türen.","f":"90 Meter bis zur Rettungskapsel. Er hat 92."},"NECRONOMICON":{"n":"BORDBUCH","d":"Schließe einen beliebigen Spieler deiner Wahl aus.","f":"Eintrag 16: „Starte Selbstzerstörungssequenz. Liebt eure Katze.\""},"OOPS":{"n":"HOPPLA!","d":"Zeige allen anderen Spielern deine gesamte Hand.","f":"Der Handschuh ist rutschig. Karten fallen mit der Rückseite nach oben — aber diese landete mit dem Gesicht nach oben."},"TEMPTATION":{"n":"VERSUCHUNG","d":"Tausche 1 Karte mit einem beliebigen Spieler deiner Wahl, wenn er nicht in Quarantäne ist. Dein Zug endet.","f":"Die Kapsel lockt. Es scheint warm. Es scheint zu atmen."},"FLAMETHROWER":{"n":"FLAMMENWERFER","d":"Ein benachbarter Spieler scheidet aus dem Spiel aus.","f":"Ich schwöre, ich verbrenne jeden, der näher kommt."},"BLIND_DATE":{"n":"BLINDES DATE","d":"Tausche 1 Karte aus deiner Hand mit der obersten Karte des Stapels, lege dabei Panikkarten ab.","f":"Der Automat gibt ein zufälliges Schicksal aus. Keine Rückgabe."},"OLD_ROPES":{"n":"ALTE SEILE","d":"Diese nutzlosen Seile reißen beim kleinsten Anstoß! Alle gespielten Quarantänekarten werden abgelegt.","f":"In Eile gebunden. Und genauso schnell beendet."},"LOVECRAFT":{"n":"ERSTER OFFIZIER","d":"Sieh die Karten in der Hand eines beliebigen Spielers.","f":"Die älteste und stärkste Angst ist die Angst vor dem Unbekannten. Und hier stehen wir davor."},"WHAT_A_PARTY":{"n":"DAS NENNT IHR EINE PARTY?","d":"Alle gespielten Quarantäne- und Verbarrikadierte-Tür-Karten werden abgelegt. Dann tauschen alle Spieler, beginnend mit dir im Uhrzeigersinn, paarweise die Plätze.","f":"Der Stroboskop blinkt. Jemand tanzt. Jemand fast."}}},"fr":{"title":"LA CHOSE","htmlTitle":"LA CHOSE — Protocole d'Infection","metaDesc":"Simulateur numérique local du jeu de société dans le style Jackbox. L'hôte s'affiche sur TV / Android TV / tablette ; les joueurs rejoignent depuis leur téléphone via un QR code. 4–12 joueurs, Wi-Fi, sans inscription.","heroRec":"REC · JOURNAL DE BORD · SESSION OUVERTE","heroTag":"Un écran au mur, les téléphones en manettes. <b>Trouve l'infecté</b> tant que le vaisseau respire encore.","heroSub":"Simulateur numérique local d'un jeu de société dans le style Jackbox. Un équipage de huit. Huit biosignatures. Plus une autre qui ne devrait pas être là.","vPlayTV":"tablette / TV","vReg":"pas besoin","ctaPlay":"Google Play · tablette / TV","ctaGameplay":"Gameplay","ctaDeck":"Le deck","s1k":"// signal du bord","s1h":"Partie en direct","s1sub":"Une vraie partie autour d'une table : un portable ou un hôte Android sur l'écran commun — et les téléphones des joueurs.","cap":"la table commune — ce que tout le monde voit. Les secrets restent sur les téléphones.","ytTag":"▶ ENREGISTREMENT DE PARTIE · YOUTUBE","s2k":"// protocole du tour","s2h":"Phases du tour","s2sub":"Chaque tour compte trois phases obligatoires. Impossible d'en sauter une — le vaisseau ne le permet pas.","p1n":"PHASE 1","p1h":"Pioche","p1p":"Tu prends la carte du dessus de la pioche. Si c'est une carte de PANIQUE, elle se joue aussitôt.","p2n":"PHASE 2","p2h":"Joue","p2p":"Tu joues une carte d'action — ou tu défausses. Les cartes de défense ne se jouent pas ici ; ce sont des réactions.","p3n":"PHASE 3","p3h":"Échange","p3p":"Tu passes une carte au voisin. Il pare avec une défense — ou l'accepte. Ce qui arrive dans ta main y reste. Pour toujours.","shipNote":"<b>◆ La règle clé :</b> c'est par l'échange que <b>La Chose</b> propage l'infection. Chaque joueur devient complice, porteur ou victime — parfois sans le savoir.","s3k":"// distribution","s3h":"Télécharger l'hôte","s3sub":"L'hôte, c'est la « table ». Les joueurs n'installent rien : ils rejoignent depuis le téléphone via un QR code.","metaAndroid":"TABLETTE / ANDROID TV","featBadge":"RECOMMANDÉ","hostNote":"<b>Android, c'est l'hôte</b>, pas le client. Une tablette ou un boîtier Android TV remplace le portable : il lance le même serveur Ktor et affiche la table commune sur le grand écran. Les joueurs rejoignent toujours depuis leur téléphone via le navigateur et un QR code — ils n'installent rien.","s4k":"// arsenal de bord","s4h":"Le deck","s4sub":"Trois types de cartes. Les actions se jouent à ton tour, la défense réagit à celui des autres, la panique se pioche à la place d'une carte normale et se déclenche aussitôt.","tabAct":"Actions · 14","tabDef":"Défense · 5","tabPan":"Panique · 12","grpAct":"🟠 Actions — se jouent en phase 2","grpDef":"🟢 Défense — réaction au tour d'autrui","grpPan":"🟣 Panique — se déclenche aussitôt","tagAct":"action","tagDefEx":"défense · échange","tagDefMove":"défense · déplacement","tagDefFlame":"défense · lance-flammes","tagPan":"panique","noteDef":"◆ La défense ne se joue pas à ton tour — seulement en réaction. Chaque carte de défense te rapporte <b>+1 carte</b> de la pioche en compensation.","notePanic":"<b>⚠ La panique</b> se pioche dans un paquet à part au lieu d'une carte normale. Elle se joue aussitôt — impossible de la défausser, de la garder ou de s'en défendre à l'avance. La panique ignore la quarantaine. La panique ne connaît pas les portes.","s5k":"// briefing","s5h":"Comment jouer","step1":"L'hôte lance l'appli sur une <b>tablette, Android TV, un portable ou un Steam Deck</b> — l'écran part sur le grand affichage.","step2":"Les joueurs scannent le <b>QR code</b> à l'écran avec leur téléphone <i>(Chrome / Firefox)</i>. Sans installation.","step3":"Distribution, tours, échanges — tout <b>depuis le téléphone</b>. Le grand écran est la mémoire commune du vaisseau, sans secrets.","reqH":"Configuration","reqHostH":"🖥️ Hôte","reqHostP":"tablette / Android TV / n'importe quel portable / Steam Deck avec Wi-Fi","reqPlayersH":"📱 Joueurs","reqPlayersP":"un téléphone avec Chrome ou Firefox (Safari non pris en charge)","reqNetH":"📡 Réseau","reqNetP":"un Wi-Fi commun — le vaisseau fonctionne sans connexion à l'extérieur","footQuote":"« Surtout ne me passe rien de vert. »","lnkPrivacy":"Confidentialité","bStatus":"STATUT","bPlayers":"JOUEURS","bNet":"RÉSEAU","bReg":"INSCRIPTION","bLic":"LICENCE","sub":"PROTOCOLE D'INFECTION","cards":{"MISS":{"n":"RATÉ !","d":"Refusez un échange. À votre place, le joueur suivant échange. Piochez 1 carte action.","f":"— Pas aujourd'hui, chérie. Peut-être une autre fois."},"GET_OUT":{"n":"DEHORS !","d":"Échangez de place avec n'importe quel joueur (hors quarantaine).","f":"Le sas s'ouvre dans 3 secondes. Pas le temps pour une combinaison."},"BARRICADED_DOOR":{"n":"PORTE BARRICADÉE","d":"Placez cette carte entre vous et un joueur adjacent. Aucune action ni échange ne peut avoir lieu entre vous.","f":"Soudée, clouée, peinte. Quelqu'un ne voulait vraiment pas que ça sorte."},"ANALYSIS":{"n":"ANALYSE","d":"Regardez toutes les cartes de la main d'un joueur adjacent choisi.","f":"…voyons maintenant qui vous êtes vraiment."},"STAY_HERE":{"n":"JE RESTE LÀ !","d":"Annulez l'effet de Changez de place ! ou Sauve-toi ! si vous en étiez la cible. Piochez 1 carte action.","f":"J'ai une chaise. J'ai une lampe. J'ai un pistolet sur les genoux. Je ne bouge pas."},"FORGETFULNESS":{"n":"OUBLI","d":"Défaussez 3 cartes de votre main et piochez 3 nouvelles cartes action. Défaussez les cartes panique rencontrées.","f":"Je crois être déjà venu ici. Je crois avoir eu un nom."},"NO_BBQ":{"n":"PAS DE BARBECUE !","d":"Annulez l'effet du lance-flammes si vous en étiez la cible. Piochez 1 carte action.","f":"La combinaison résiste à 1200°C. Contre cette chose — environ cinq secondes."},"NO_THANKS":{"n":"NON, MERCI !","d":"Refusez un échange. Piochez 1 carte action.","f":"Une vrille pousse dans le verre. Je ne bois pas."},"FEAR":{"n":"PEUR","d":"Refusez un échange et regardez la carte refusée. Piochez 1 carte action.","f":"— Dave ! Ouvre le sas ! — …Dave."},"CHAIN_REACTION":{"n":"RÉACTION EN CHAÎNE","d":"Chaque joueur passe simultanément 1 carte au joueur suivant, en ignorant quarantaines et portes barricadées. Votre tour se termine.","f":"Le signal a traversé toutes les communications internes. Personne ne peut rester silencieux."},"THREE_FOUR":{"n":"…TROIS, QUATRE…","d":"…ouvrez grand la porte ! Toutes les portes barricadées sont défaussées.","f":"Les planches cèdent au troisième coup. Au deuxième — si vous frappez avec quelque chose qui n'est plus humain."},"ONE_TWO":{"n":"UN, DEUX…","d":"…La Chose a surgi des profondeurs ! Échangez de place avec le troisième joueur à gauche ou à droite (votre choix). Ignorez les portes barricadées.","f":"Quelque chose est sous la grille du sol. Et aujourd'hui, il a décidé qu'il en avait assez d'être en dessous."},"JUST_BETWEEN_US":{"n":"ENTRE NOUS…","d":"Montrez toutes vos cartes à un joueur adjacent de votre choix.","f":"Canal chiffré. Garantit que seul il entendra. Et ce qu'il est devenu."},"LETS_BE_FRIENDS":{"n":"SOYONS AMIS !","d":"Échangez 1 carte avec n'importe quel joueur (hors quarantaine).","f":"Le gant est chaud. Trop chaud. Et quelque chose à l'intérieur bouge."},"CONFESSION_TIME":{"n":"L'HEURE DES AVEUX","d":"À partir de vous et dans l'ordre des tours, chaque joueur montre ou non toutes ses cartes aux autres.","f":"Sous la lampe, tout le monde est suspect. Même la lumière."},"AXE":{"n":"HACHE","d":"Retirez la quarantaine de vous-même ou d'un adjacent, ou retirez une porte barricadée entre vous.","f":"La vitre du cabinet d'urgence était déjà brisée quand je suis arrivé."},"SWAP_PLACES":{"n":"CHANGEZ DE PLACE !","d":"Échangez de place avec un joueur adjacent (hors quarantaine). Ignorez toutes les portes barricadées.","f":"Le couloir a la même apparence des deux côtés. Ou pas ?"},"QUARANTINE":{"n":"QUARANTAINE","d":"Jouez sur vous-même ou un joueur adjacent. Pendant ses 3 prochains tours, le joueur en quarantaine ne peut pas échanger de cartes ni jouer de cartes action.","f":"Attaché. Crier dans le bâillon est inutile — personne n'entendra."},"SUSPICION":{"n":"SUSPICION","d":"Regardez 1 carte au hasard dans la main d'un joueur adjacent.","f":"Quand nous nous sommes assis — il était gaucher. Depuis, il a saisi sa tasse de la droite trois fois."},"REVERSE":{"n":"QUELQUE CHOSE BOUGE","d":"Change le sens des tours et des échanges.","f":"Quelque chose bouge plus loin dans le couloir. Lentement. Mais clairement vers nous."},"PERSISTENCE":{"n":"PERSISTANCE","d":"Piochez 3 cartes action, gardez-en 1 et défaussez les 2 autres. Puis jouez ou défaussez 1 carte.","f":"Le sang n'est pas le mien. Enfin, pas tout."},"WHISKY":{"n":"WHISKY","d":"Montrez toutes vos cartes aux autres joueurs. Ne peut être joué que sur vous-même.","f":"En apesanteur, les glaçons ne tintent pas. Mais le verre dérive exactement où il doit aller."},"RUN_AWAY":{"n":"SAUVE-TOI D'ICI !","d":"Échangez de place avec n'importe quel joueur (hors quarantaine). Ignorez toutes les portes barricadées.","f":"90 mètres jusqu'à la capsule de sauvetage. Il en a 92."},"NECRONOMICON":{"n":"JOURNAL DE BORD","d":"Éliminez n'importe quel joueur.","f":"Journal 16 : « Lancement de l'autodestruction. Embrassez votre chat. »"},"OOPS":{"n":"OUPS !","d":"Montrez toutes vos cartes aux autres joueurs.","f":"Le gant est glissant. Les cartes tombent face cachée — mais celle-ci a atterri face visible."},"TEMPTATION":{"n":"TENTATION","d":"Échangez 1 carte avec n'importe quel joueur (hors quarantaine). Votre tour se termine.","f":"La capsule attire. Elle semble chaude. Elle semble respirer."},"FLAMETHROWER":{"n":"LANCE-FLAMMES","d":"Un joueur adjacent est éliminé de la partie.","f":"Je jure que je brûlerai quiconque s'approchera de moi."},"BLIND_DATE":{"n":"RENDEZ-VOUS AVEUGLE","d":"Échangez 1 carte de votre main avec la carte du dessus de la pioche, en défaussant les cartes panique rencontrées.","f":"La machine dispense un destin aléatoire. Non remboursable."},"OLD_ROPES":{"n":"VIEILLES CORDES","d":"Ces cordes inutiles cèdent au moindre contact ! Toutes les quarantaines sont défaussées.","f":"Noué à la hâte. Terminé tout aussi vite."},"LOVECRAFT":{"n":"SECOND MAÎTRE","d":"Regardez les cartes de la main de n'importe quel joueur.","f":"La peur la plus ancienne et la plus forte est la peur de l'inconnu. Et nous voilà face à elle."},"WHAT_A_PARTY":{"n":"QUELLE FÊTE !","d":"Toutes les quarantaines et portes barricadées sont défaussées. Puis tous les joueurs échangent leurs places deux par deux dans le sens des aiguilles d'une montre.","f":"Le stroboscope clignote. Quelqu'un danse. Quelqu'un danse presque."}}},"pt-br":{"title":"A COISA","htmlTitle":"A COISA — Protocolo de Infecção","metaDesc":"Simulador digital local do jogo de tabuleiro no estilo Jackbox. O host fica na TV / Android TV / tablet; os jogadores entram pelo celular via QR code. 4–12 jogadores, Wi-Fi, sem cadastro.","heroRec":"REC · DIÁRIO DE BORDO · SESSÃO ABERTA","heroTag":"Uma tela na parede, celulares como controles. <b>Encontre o infectado</b> enquanto a nave ainda respira.","heroSub":"Simulador digital local de um jogo de tabuleiro no estilo Jackbox. Uma tripulação de oito. Oito biossinaturas. E mais uma que não deveria estar ali.","vPlayTV":"tablet / TV","vReg":"não precisa","ctaPlay":"Google Play · tablet / TV","ctaGameplay":"Gameplay","ctaDeck":"O baralho","s1k":"// sinal de bordo","s1h":"Partida ao vivo","s1sub":"Uma partida real em uma mesa: um notebook ou host Android na tela compartilhada — e os celulares dos jogadores.","cap":"a mesa compartilhada — o que todos veem. Os segredos ficam nos celulares.","ytTag":"▶ GRAVAÇÃO DA PARTIDA · YOUTUBE","s2k":"// protocolo do turno","s2h":"Fases do turno","s2sub":"Cada turno tem três fases obrigatórias. Não dá para pular nenhuma — a nave não permite.","p1n":"FASE 1","p1h":"Compra carta","p1p":"Você pega a carta do topo do baralho. Se for uma carta de PÂNICO, ela é jogada imediatamente.","p2n":"FASE 2","p2h":"Joga","p2p":"Você joga uma carta de ação — ou descarta. As cartas de defesa não são jogadas aqui; são uma reação.","p3n":"FASE 3","p3h":"Troca","p3p":"Você passa uma carta ao vizinho. Ele rebate com defesa — ou aceita. O que cai na sua mão fica. Para sempre.","shipNote":"<b>◆ A regra principal:</b> é pela troca que <b>A Coisa</b> espalha a infecção. Cada jogador vira cúmplice, portador ou vítima — às vezes sem saber.","s3k":"// distribuição","s3h":"Baixar o host","s3sub":"O host é a \"mesa\". Os jogadores não instalam nada: entram pelo celular via QR code.","metaAndroid":"TABLET / ANDROID TV","featBadge":"RECOMENDADO","hostNote":"<b>O Android é o host</b>, não o cliente. Um tablet ou aparelho Android TV substitui o notebook: sobe o mesmo servidor Ktor e mostra a mesa compartilhada na tela grande. Os jogadores continuam entrando pelo celular via navegador e QR code — não instalam nada.","s4k":"// arsenal de bordo","s4h":"O baralho","s4sub":"Três tipos de carta. Ações são jogadas no seu turno, defesa reage ao dos outros, pânico é comprado no lugar de uma carta normal e dispara na hora.","tabAct":"Ações · 14","tabDef":"Defesa · 5","tabPan":"Pânico · 12","grpAct":"🟠 Ações — jogadas na fase 2","grpDef":"🟢 Defesa — reação ao turno alheio","grpPan":"🟣 Pânico — dispara imediatamente","tagAct":"ação","tagDefEx":"defesa · troca","tagDefMove":"defesa · movimento","tagDefFlame":"defesa · lança-chamas","tagPan":"pânico","noteDef":"◆ A defesa não é jogada no seu turno — só como reação. Cada carta de defesa te dá <b>+1 carta</b> do baralho como compensação.","notePanic":"<b>⚠ O pânico</b> é comprado de um baralho à parte no lugar de uma carta normal. É jogado na hora — não dá para descartar, guardar nem se defender com antecedência. O pânico ignora a quarentena. O pânico não conhece portas.","s5k":"// instruções","s5h":"Como jogar","step1":"O host abre o app em um <b>tablet, Android TV, notebook ou Steam Deck</b> — a tela vai para o monitor grande.","step2":"Os jogadores escaneiam o <b>QR code</b> na tela com o celular <i>(Chrome / Firefox)</i>. Sem instalar nada.","step3":"Distribuição, turnos, trocas — tudo <b>pelo celular</b>. A tela grande é a memória compartilhada da nave, sem segredos.","reqH":"Requisitos","reqHostH":"🖥️ Host","reqHostP":"tablet / Android TV / qualquer notebook / Steam Deck com Wi-Fi","reqPlayersH":"📱 Jogadores","reqPlayersP":"um celular com Chrome ou Firefox (Safari sem suporte)","reqNetH":"📡 Rede","reqNetP":"um Wi-Fi comum — a nave funciona sem conexão externa","footQuote":"«Só não me passe nada verde.»","lnkPrivacy":"Privacidade","bStatus":"STATUS","bPlayers":"JOGADORES","bNet":"REDE","bReg":"CADASTRO","bLic":"LICENÇA","sub":"PROTOCOLO DE INFECÇÃO","cards":{"MISS":{"n":"ERROU!","d":"Recuse uma troca de cartas. Em seu lugar, o próximo jogador troca cartas. Compre 1 carta de ação.","f":"— Hoje não, querido. Quem sabe outra vez."},"GET_OUT":{"n":"SAIA DAQUI!","d":"Troque de lugar com qualquer jogador de sua escolha, se não estiver em quarentena.","f":"A câmara de ar dispara em 3 segundos. Sem tempo para o traje."},"BARRICADED_DOOR":{"n":"PORTA BARRICADA","d":"Coloque esta carta entre você e um jogador adjacente. Nenhuma ação ou troca pode ocorrer entre vocês.","f":"Soldado, pregado, pintado. Alguém realmente não queria que isso saísse."},"ANALYSIS":{"n":"ANÁLISE","d":"Veja todas as cartas na mão de um jogador adjacente escolhido.","f":"…agora vamos ver quem você realmente é."},"STAY_HERE":{"n":"FICO AQUI!","d":"Cancele o efeito de Troca de Lugar! ou Corra! se você foi seu alvo. Compre 1 carta de ação.","f":"Tenho uma cadeira. Tenho uma lâmpada. Tenho uma arma no colo. Não vou a lugar nenhum."},"FORGETFULNESS":{"n":"ESQUECIMENTO","d":"Descarte 3 cartas da sua mão e compre 3 novas cartas de ação. Descarte as cartas de pânico encontradas.","f":"Acho que já estive aqui antes. Acho que tinha um nome."},"NO_BBQ":{"n":"SEM CHURRASCO!","d":"Cancele o efeito do Lança-Chamas se você foi seu alvo. Compre 1 carta de ação.","f":"O traje aguenta até 1200°C. Contra essa coisa — uns cinco segundos."},"NO_THANKS":{"n":"NÃO, OBRIGADO!","d":"Recuse uma troca de cartas. Compre 1 carta de ação.","f":"Uma trepadeira está crescendo dentro do copo. Não vou beber."},"FEAR":{"n":"MEDO","d":"Recuse uma troca de cartas e veja a carta recusada. Compre 1 carta de ação.","f":"— Dave! Abra a câmara de ar! — …Dave."},"CHAIN_REACTION":{"n":"REAÇÃO EM CADEIA","d":"Cada jogador passa simultaneamente 1 carta ao próximo na ordem de turnos, ignorando todas as Quarentenas e Portas Barricadas. Seu turno termina.","f":"O sinal percorreu todas as comunicações internas de uma vez. Ninguém pode ficar em silêncio."},"THREE_FOUR":{"n":"…TRÊS, QUATRO…","d":"…abra bem a porta! Todas as cartas de Porta Barricada jogadas são descartadas.","f":"As tábuas quebram no terceiro golpe. No segundo — se você bater com algo que já não é humano."},"ONE_TWO":{"n":"UM, DOIS…","d":"…A Coisa emergiu das profundezas! Troque de lugar com o terceiro jogador à sua esquerda ou direita (sua escolha). Ignore todas as Portas Barricadas.","f":"Tem algo sob a grade do piso. E hoje ele decidiu que estava cansado de ficar por baixo."},"JUST_BETWEEN_US":{"n":"SÓ ENTRE NÓS…","d":"Mostre todas as suas cartas de mão a um jogador adjacente de sua escolha.","f":"Canal criptografado. Garante que só ele ouvirá. E aquilo em que ele se tornou."},"LETS_BE_FRIENDS":{"n":"VAMOS SER AMIGOS?","d":"Troque 1 carta com qualquer jogador (sua escolha), se não estiver em quarentena.","f":"A luva está quente. Quente demais. E algo dentro dela se move."},"CONFESSION_TIME":{"n":"HORA DA CONFISSÃO","d":"Começando por você na ordem de turnos, cada jogador escolhe mostrar ou não todas as suas cartas aos outros.","f":"Sob a lâmpada, todos são suspeitos. Até a luz."},"AXE":{"n":"MACHADO","d":"Remove a Quarentena de você mesmo ou de um jogador adjacente, ou remove uma Porta Barricada entre vocês.","f":"O vidro do armário de emergência já estava quebrado quando cheguei."},"SWAP_PLACES":{"n":"TROCA DE LUGAR!","d":"Troque de lugar com um jogador adjacente, se não estiver em quarentena. Ignore todas as Portas Barricadas.","f":"O corredor parece igual de ambas as extremidades. Ou não?"},"QUARANTINE":{"n":"QUARENTENA","d":"Jogue sobre você mesmo ou um jogador adjacente. Durante seus próximos 3 turnos, o jogador em quarentena não pode trocar cartas, jogar cartas de ação nem ser alvo delas.","f":"Amarrado. Gritar com uma mordaça é inútil — ninguém vai ouvir."},"SUSPICION":{"n":"SUSPEITA","d":"Veja 1 carta aleatória na mão de um jogador adjacente.","f":"Quando sentamos — ele era canhoto. Desde então pegou a caneca com a mão direita três vezes."},"REVERSE":{"n":"ALGO SE MOVE","d":"Muda a direção dos turnos e trocas para o sentido contrário.","f":"Algo se move mais adiante no corredor. Devagar. Mas definitivamente em nossa direção."},"PERSISTENCE":{"n":"PERSISTÊNCIA","d":"Compre 3 cartas de ação, fique com 1 na mão e descarte as outras 2. Em seguida, jogue ou descarte 1 carta.","f":"O sangue não é meu. Bom, não todo."},"WHISKY":{"n":"WHISKY","d":"Mostre todas as suas cartas aos outros jogadores. Esta carta só pode ser jogada sobre você mesmo.","f":"Em gravidade zero o gelo não tilinta. Mas o copo flutua exatamente para onde precisa ir."},"RUN_AWAY":{"n":"CORRA!","d":"Troque de lugar com qualquer jogador de sua escolha, se não estiver em quarentena. Ignore todas as Portas Barricadas.","f":"90 metros até a cápsula de escape. Ele tem 92."},"NECRONOMICON":{"n":"DIÁRIO DE BORDO","d":"Elimine qualquer jogador de sua escolha.","f":"Registro 16: «Iniciando sequência de autodestruição. Ame seu gato.»"},"OOPS":{"n":"OOOPS!","d":"Mostre todas as suas cartas de mão aos outros jogadores.","f":"A luva está escorregadia. As cartas caem viradas para baixo — mas esta ficou virada para cima."},"TEMPTATION":{"n":"TENTAÇÃO","d":"Troque 1 carta com qualquer jogador de sua escolha, se não estiver em quarentena. Seu turno termina.","f":"A cápsula chama. Parece quente. Parece respirar."},"FLAMETHROWER":{"n":"LANÇA-CHAMAS","d":"Um jogador adjacente é eliminado da partida.","f":"Juro que vou queimar qualquer um que chegar perto."},"BLIND_DATE":{"n":"ENCONTRO ÀS CEGAS","d":"Troque 1 carta da sua mão pela carta do topo do baralho, descartando cartas de pânico encontradas.","f":"A máquina dispensa um destino aleatório. Sem devolução."},"OLD_ROPES":{"n":"CORDAS VELHAS","d":"Essas cordas inúteis se partem com o menor toque! Todas as cartas de Quarentena jogadas são descartadas.","f":"Amarradas com pressa. E terminaram igual."},"LOVECRAFT":{"n":"IMEDIATO","d":"Veja as cartas na mão de qualquer jogador escolhido.","f":"O medo mais antigo e forte é o medo do desconhecido. E aqui estamos diante dele."},"WHAT_A_PARTY":{"n":"ISSO QUE É FESTA?","d":"Todas as cartas de Quarentena e Porta Barricada jogadas são descartadas. Então, começando por você no sentido horário, todos os jogadores trocam de lugar em pares.","f":"O estroboscópio pisca. Alguém está dançando. Alguém quase está dançando."}}},"pl":{"title":"TO COŚ","htmlTitle":"TO COŚ — Protokół Infekcji","metaDesc":"Lokalny cyfrowy symulator gry planszowej w stylu Jackbox. Host na TV / Android TV / tablecie — gracze dołączają z telefonu przez kod QR. 4–12 graczy, Wi-Fi, bez rejestracji.","heroRec":"REC · DZIENNIK POKŁADOWY · SESJA OTWARTA","heroTag":"Jeden ekran na ścianie, telefony jako pady. <b>Znajdź zarażonego</b>, póki statek jeszcze oddycha.","heroSub":"Lokalny cyfrowy symulator gry planszowej w stylu Jackbox. Załoga ośmiu. Osiem biosygnatur. Plus jeszcze jedna, której być nie powinno.","vPlayTV":"tablet / TV","vReg":"niepotrzebna","ctaPlay":"Google Play · tablet / TV","ctaGameplay":"Rozgrywka","ctaDeck":"Talia","s1k":"// sygnał z pokładu","s1h":"Rozgrywka na żywo","s1sub":"Prawdziwa partia przy jednym stole: laptop lub host Android na wspólnym ekranie — i telefony graczy.","cap":"wspólny stół — to, co widzą wszyscy. Sekrety zostają w telefonach.","ytTag":"▶ NAGRANIE PARTII · YOUTUBE","s2k":"// protokół tury","s2h":"Fazy tury","s2sub":"Każda tura ma trzy obowiązkowe fazy. Żadnej nie da się pominąć — statek na to nie pozwoli.","p1n":"FAZA 1","p1h":"Dobiera kartę","p1p":"Bierzesz wierzchnią kartę z talii. Jeśli to karta PANIKI — gra się ją natychmiast.","p2n":"FAZA 2","p2h":"Zagrywa","p2p":"Zagrywasz jedną kartę akcji — albo odrzucasz. Kart obrony tu się nie gra; to reakcja.","p3n":"FAZA 3","p3h":"Wymienia","p3p":"Podajesz kartę sąsiadowi. Odbija ją obroną — albo przyjmuje. Co trafi do ręki, zostaje. Na zawsze.","shipNote":"<b>◆ Główna zasada:</b> to właśnie przez wymianę <b>To Coś</b> przenosi infekcję. Każdy gracz staje się wspólnikiem, nosicielem albo ofiarą — czasem nieświadomie.","s3k":"// dystrybucja","s3h":"Pobierz hosta","s3sub":"Host to „stół”. Gracze nic nie instalują: wchodzą z telefonu przez kod QR.","metaAndroid":"TABLET / ANDROID TV","featBadge":"POLECANE","hostNote":"<b>Android to host</b>, a nie klient. Tablet lub przystawka Android TV zastępują laptopa: stawiają ten sam serwer Ktor i pokazują wspólny stół na dużym ekranie. Gracze nadal dołączają z telefonu przez przeglądarkę i kod QR — nic nie instalują.","s4k":"// arsenał pokładowy","s4h":"Talia","s4sub":"Trzy typy kart. Akcje gra się w swojej turze, obrona reaguje na cudzą, panika dobierana jest zamiast zwykłej karty i odpala się od razu.","tabAct":"Akcje · 14","tabDef":"Obrona · 5","tabPan":"Panika · 12","grpAct":"🟠 Akcje — grane w fazie 2","grpDef":"🟢 Obrona — reakcja na cudzą turę","grpPan":"🟣 Panika — odpala się natychmiast","tagAct":"akcja","tagDefEx":"obrona · wymiana","tagDefMove":"obrona · przemieszczenie","tagDefFlame":"obrona · miotacz ognia","tagPan":"panika","noteDef":"◆ Obrony nie gra się w swojej turze — tylko jako reakcję. Każda karta obrony daje ci <b>+1 kartę</b> z talii w ramach rekompensaty.","notePanic":"<b>⚠ Panika</b> dobierana jest z osobnej talii zamiast zwykłej karty. Gra się ją od razu — nie da się jej odrzucić, zatrzymać ani obronić z wyprzedzeniem. Panika ignoruje kwarantannę. Panika nie zna drzwi.","s5k":"// instruktaż","s5h":"Jak grać","step1":"Host uruchamia aplikację na <b>tablecie, Android TV, laptopie lub Steam Decku</b> — obraz idzie na duży ekran.","step2":"Gracze skanują <b>kod QR</b> z ekranu telefonem <i>(Chrome / Firefox)</i>. Bez instalacji.","step3":"Rozdawanie, tury, wymiany — wszystko <b>z telefonu</b>. Duży ekran to wspólna pamięć statku, bez sekretów.","reqH":"Wymagania","reqHostH":"🖥️ Host","reqHostP":"tablet / Android TV / dowolny laptop / Steam Deck z Wi-Fi","reqPlayersH":"📱 Gracze","reqPlayersP":"telefon z Chrome lub Firefox (Safari niewspierane)","reqNetH":"📡 Sieć","reqNetP":"wspólne Wi-Fi — statek działa bez połączenia ze światem","footQuote":"„Tylko nie podawaj mi niczego zielonego.”","lnkPrivacy":"Prywatność","bStatus":"STATUS","bPlayers":"GRACZE","bNet":"SIEĆ","bReg":"REJESTRACJA","bLic":"LICENCJA","sub":"PROTOKÓŁ INFEKCJI","cards":{"MISS":{"n":"PUDŁO!","d":"Odmów wymiany. Zamiast ciebie, następny gracz wymienia karty. Dobierz 1 kartę akcji.","f":"— Nie dziś, kochanie. Może innym razem."},"GET_OUT":{"n":"WYNOŚ SIĘ!","d":"Zamień miejsca z dowolnym graczem (poza kwarantanną).","f":"Śluza otwiera się za 3 sekundy. Nie ma czasu na skafander."},"BARRICADED_DOOR":{"n":"ZABARYKADOWANE DRZWI","d":"Umieść tę kartę między sobą a sąsiednim graczem. Żadne akcje ani wymiany nie mogą między wami zachodzić.","f":"Spawane, przybite, zamalowane. Ktoś naprawdę nie chciał, żeby to wyszło."},"ANALYSIS":{"n":"ANALIZA","d":"Obejrzyj wszystkie karty w ręce wybranego sąsiedniego gracza.","f":"…zobaczmy teraz, kim naprawdę jesteś."},"STAY_HERE":{"n":"JA TU ZOSTANĘ!","d":"Anuluj efekt Zamień miejsca! lub Uciekaj!, jeśli byłeś celem. Dobierz 1 kartę akcji.","f":"Mam krzesło. Mam lampę. Mam pistolet na kolanach. Nigdzie nie idę."},"FORGETFULNESS":{"n":"ZAPOMNIENIE","d":"Odrzuć 3 karty z ręki i dobierz 3 nowe karty akcji. Odrzuć napotkane karty paniki.","f":"Chyba już tu byłem. Chyba miałem jakieś imię."},"NO_BBQ":{"n":"BEZ GRILLA!","d":"Anuluj efekt miotacza ognia, jeśli byłeś celem. Dobierz 1 kartę akcji.","f":"Kombinezon wytrzymuje 1200°C. Przeciw tej rzeczy — jakieś pięć sekund."},"NO_THANKS":{"n":"NIE, DZIĘKUJĘ!","d":"Odmów wymiany kart. Dobierz 1 kartę akcji.","f":"Z kieliszka wyrasta pęd. Nie piję."},"FEAR":{"n":"STRACH","d":"Odmów wymiany i obejrzyj odmówioną kartę. Dobierz 1 kartę akcji.","f":"— Dave! Otwórz śluzę! — …Dave."},"CHAIN_REACTION":{"n":"REAKCJA ŁAŃCUCHOWA","d":"Każdy gracz jednocześnie przekazuje 1 kartę następnemu graczowi, ignorując kwarantanny i drzwi. Twoja tura kończy się.","f":"Sygnał przeszedł przez wszystkie wewnętrzne kanały. Nikt nie może milczeć."},"THREE_FOUR":{"n":"…TRZY, CZTERY…","d":"…otwórzcie drzwi na oścież! Wszystkie zabarykadowane drzwi zostają odrzucone.","f":"Deski pękają przy trzecim uderzeniu. Przy drugim — jeśli bijesz czymś, co już nie jest człowiekiem."},"ONE_TWO":{"n":"RAZ, DWA…","d":"…To Coś wynurzyło się z głębin! Zamień miejsca z trzecim graczem po lewej lub prawej (twój wybór). Ignoruj zabarykadowane drzwi.","f":"Coś jest pod kratką podłogi. I dziś zdecydowało, że ma dość bycia na dole."},"JUST_BETWEEN_US":{"n":"MIĘDZY NAMI…","d":"Pokaż wszystkie karty z ręki wybranemu sąsiedniemu graczowi.","f":"Szyfrowany kanał. Gwarantuje, że tylko on usłyszy. I to, czym się stał."},"LETS_BE_FRIENDS":{"n":"BĄDŹMY PRZYJACIÓŁMI!","d":"Wymień 1 kartę z dowolnym graczem (poza kwarantanną).","f":"Rękawica jest ciepła. Za ciepła. I coś w środku się porusza."},"CONFESSION_TIME":{"n":"CZAS WYZNAŃ","d":"Zaczynając od ciebie, każdy gracz po kolei pokazuje lub nie swoje karty pozostałym.","f":"Pod lampą każdy jest podejrzany. Nawet światło."},"AXE":{"n":"SIEKIERA","d":"Usuń kwarantannę z siebie lub sąsiada, lub usuń zabarykadowane drzwi między wami.","f":"Szklana gablota awaryjna była już rozbita, gdy dotarłem na miejsce."},"SWAP_PLACES":{"n":"ZAMIEŃ MIEJSCA!","d":"Zamień miejsca z sąsiednim graczem (poza kwarantanną). Ignoruj zabarykadowane drzwi.","f":"Korytarz wygląda tak samo z obu stron. Czy na pewno?"},"QUARANTINE":{"n":"KWARANTANNA","d":"Zagraj na siebie lub sąsiedniego gracza. Przez kolejne 3 tury gracz w kwarantannie nie może wymieniać kart ani grać kart akcji.","f":"Przywiązany. Krzyczenie w knebel jest bezsensowne — nikt nie usłyszy."},"SUSPICION":{"n":"PODEJRZENIE","d":"Obejrzyj 1 losową kartę w ręce sąsiedniego gracza.","f":"Kiedy usiedliśmy — był leworęczny. Od tamtej pory trzy razy podniósł kubek prawą ręką."},"REVERSE":{"n":"COŚ SIĘ PORUSZA","d":"Zmienia kierunek tur i wymian na przeciwny.","f":"Coś porusza się dalej w korytarzu. Powoli. Ale wyraźnie w naszą stronę."},"PERSISTENCE":{"n":"WYTRWAŁOŚĆ","d":"Dobierz 3 karty akcji, zachowaj 1 i odrzuć pozostałe 2. Następnie zagraj lub odrzuć 1 kartę.","f":"Krew nie jest moja. No, nie cała."},"WHISKY":{"n":"WHISKY","d":"Pokaż wszystkie swoje karty innym graczom. Można zagrać tylko na siebie.","f":"W nieważkości lód nie brzęczy. Ale szklanka dryfuje dokładnie tam, gdzie powinna."},"RUN_AWAY":{"n":"UCIEKAJ STĄD!","d":"Zamień miejsca z dowolnym graczem (poza kwarantanną). Ignoruj zabarykadowane drzwi.","f":"90 metrów do kapsuły ratunkowej. On ma 92."},"NECRONOMICON":{"n":"DZIENNIK POKŁADOWY","d":"Wyeliminuj dowolnego gracza.","f":"Dziennik 16: «Uruchamiam samozniszczenie. Pozdrowienia dla kota.»"},"OOPS":{"n":"OJEJ!","d":"Pokaż wszystkie karty z ręki innym graczom.","f":"Rękawica jest śliska. Karty spadają zakryte — ale ta wylądowała odkryta."},"TEMPTATION":{"n":"POKUSA","d":"Wymień 1 kartę z dowolnym graczem (poza kwarantanną). Twoja tura kończy się.","f":"Kapsuła kusi. Wydaje się ciepła. Wydaje się oddychać."},"FLAMETHROWER":{"n":"MIOTACZ OGNIA","d":"Sąsiedni gracz zostaje wyeliminowany z gry.","f":"Przysięgam, że spalę każdego, kto się zbliży."},"BLIND_DATE":{"n":"RANDKA W CIEMNO","d":"Wymień 1 kartę z ręki z wierzchnią kartą talii, odrzucając napotkane karty paniki.","f":"Maszyna losuje los. Bez zwrotu."},"OLD_ROPES":{"n":"STARE LINY","d":"Te bezużyteczne liny rwą się przy najmniejszym dotknięciu! Wszystkie kwarantanny zostają odrzucone.","f":"Zawiązane w pośpiechu. I zakończone równie szybko."},"LOVECRAFT":{"n":"PIERWSZY OFICER","d":"Obejrzyj karty w ręce dowolnego gracza.","f":"Najstarsza i najsilniejsza trwoga to strach przed nieznanym. I oto stoimy przed nim."},"WHAT_A_PARTY":{"n":"CO ZA IMPREZA!","d":"Wszystkie kwarantanny i zabarykadowane drzwi zostają odrzucone. Następnie, zaczynając od ciebie, gracze zamieniają się miejscami parami.","f":"Stroboskop miga. Ktoś tańczy. Ktoś prawie tańczy."}}},"tr":{"title":"O ŞEY","htmlTitle":"O ŞEY — Enfeksiyon Protokolü","metaDesc":"Jackbox tarzı masa oyununun yerel dijital simülatörü. Host TV / Android TV / tablette çalışır; oyuncular telefonlarından QR kodla katılır. 4–12 oyuncu, Wi-Fi, kayıt gerekmez.","heroRec":"REC · SEYİR DEFTERİ · OTURUM AÇIK","heroTag":"Duvarda tek ekran, telefonlar kumanda. Gemi hâlâ nefes alırken <b>bulaşmış olanı bul</b>.","heroSub":"Jackbox tarzı bir masa oyununun yerel dijital simülatörü. Sekiz kişilik mürettebat. Sekiz biyoimza. Bir de orada olmaması gereken bir tane daha.","vPlayTV":"tablet / TV","vReg":"gerekmez","ctaPlay":"Google Play · tablet / TV","ctaGameplay":"Oynanış","ctaDeck":"Deste","s1k":"// gemiden sinyal","s1h":"Canlı oyun","s1sub":"Tek masada gerçek bir oyun: ortak ekranda bir dizüstü ya da Android host — ve oyuncuların telefonları.","cap":"ortak masa — herkesin gördüğü. Sırlar telefonlarda kalır.","ytTag":"▶ OYUN KAYDI · YOUTUBE","s2k":"// tur protokolü","s2h":"Tur aşamaları","s2sub":"Her turun üç zorunlu aşaması vardır. Hiçbiri atlanamaz — gemi izin vermez.","p1n":"AŞAMA 1","p1h":"Kart çeker","p1p":"Desteden en üstteki kartı alırsın. PANİK kartı çıkarsa hemen oynanır.","p2n":"AŞAMA 2","p2h":"Oynar","p2p":"Bir eylem kartı oynarsın — ya da atarsın. Savunma kartları burada oynanmaz; onlar bir tepkidir.","p3n":"AŞAMA 3","p3h":"Takas eder","p3p":"Komşuna bir kart verirsin. O savunmayla savar — ya da kabul eder. Eline geçen kalır. Sonsuza dek.","shipNote":"<b>◆ Temel kural:</b> <b>O Şey</b> enfeksiyonu tam da takasla yayar. Her oyuncu suç ortağı, taşıyıcı ya da kurban olur — bazen farkında olmadan.","s3k":"// dağıtım","s3h":"Host'u indir","s3sub":"Host \"masa\"dır. Oyuncular hiçbir şey kurmaz: telefondan QR kodla katılırlar.","metaAndroid":"TABLET / ANDROID TV","featBadge":"ÖNERİLEN","hostNote":"<b>Android host'tur</b>, istemci değil. Tablet ya da Android TV kutusu dizüstünün yerini alır: aynı Ktor sunucusunu çalıştırır ve ortak masayı büyük ekranda gösterir. Oyuncular yine telefondan tarayıcı ve QR kodla katılır — hiçbir şey kurmazlar.","s4k":"// gemi cephaneliği","s4h":"Deste","s4sub":"Üç kart türü. Eylemler kendi turunda oynanır, savunma başkasınınkine tepki verir, panik normal kart yerine çekilir ve anında tetiklenir.","tabAct":"Eylemler · 14","tabDef":"Savunma · 5","tabPan":"Panik · 12","grpAct":"🟠 Eylemler — 2. aşamada oynanır","grpDef":"🟢 Savunma — başkasının turuna tepki","grpPan":"🟣 Panik — anında tetiklenir","tagAct":"eylem","tagDefEx":"savunma · takas","tagDefMove":"savunma · yer değiştirme","tagDefFlame":"savunma · alev makinesi","tagPan":"panik","noteDef":"◆ Savunma kendi turunda oynanmaz — yalnızca tepki olarak. Her savunma kartı telafi olarak desteden <b>+1 kart</b> verir.","notePanic":"<b>⚠ Panik</b> normal kart yerine ayrı bir desteden çekilir. Anında oynanır — atılamaz, saklanamaz, önceden savunulamaz. Panik karantinayı dinlemez. Panik kapı tanımaz.","s5k":"// brifing","s5h":"Nasıl oynanır","step1":"Host uygulamayı bir <b>tablet, Android TV, dizüstü ya da Steam Deck</b> üzerinde açar — görüntü büyük ekrana gider.","step2":"Oyuncular ekrandaki <b>QR kodu</b> telefonlarıyla okutur <i>(Chrome / Firefox)</i>. Kurulum gerekmez.","step3":"Dağıtım, turlar, takaslar — hepsi <b>telefondan</b>. Büyük ekran geminin ortak hafızasıdır, sırsız.","reqH":"Gereksinimler","reqHostH":"🖥️ Host","reqHostP":"tablet / Android TV / herhangi bir dizüstü / Wi-Fi'li Steam Deck","reqPlayersH":"📱 Oyuncular","reqPlayersP":"Chrome veya Firefox'lu bir telefon (Safari desteklenmez)","reqNetH":"📡 Ağ","reqNetP":"ortak bir Wi-Fi — gemi dışarıya bağlanmadan çalışır","footQuote":"«Sadece bana yeşil bir şey uzatma.»","lnkPrivacy":"Gizlilik","bStatus":"DURUM","bPlayers":"OYUNCU","bNet":"AĞ","bReg":"KAYIT","bLic":"LİSANS","sub":"ENFEKSİYON PROTOKOLÜ","cards":{"MISS":{"n":"ISKALADI!","d":"Değişimi reddet. Senin yerine bir sonraki oyuncu değişim yapar. 1 aksiyon kartı çek.","f":"— Bugün değil, tatlım. Belki başka zaman."},"GET_OUT":{"n":"ÇIKIP GİT!","d":"Karantinada olmayan herhangi bir oyuncuyla yer değiştir.","f":"Hava kilidi 3 saniyede açılıyor. Uzay kıyafeti için zaman yok."},"BARRICADED_DOOR":{"n":"BARİKAT KAPI","d":"Bu kartı kendin ile komşu oyuncu arasına yerleştir. Aranızda hiçbir aksiyon veya değişim gerçekleşemez.","f":"Kaynak yapılmış, çivilenmiş, boyanmış. Biri gerçekten bunun çıkmasını istemiyordu."},"ANALYSIS":{"n":"ANALİZ","d":"Seçilen komşu oyuncunun elindeki tüm kartlara bak.","f":"…şimdi gerçekte kim olduğunu görelim."},"STAY_HERE":{"n":"BEN BURADAYIM!","d":"Hedef olduğun Yer Değiştir! veya Kaçın! etkisini iptal et. 1 aksiyon kartı çek.","f":"Bir sandalyem var. Bir lambam var. Dizimde bir silahım var. Hiçbir yere gitmiyorum."},"FORGETFULNESS":{"n":"UNUTKANLIK","d":"Elinden 3 kart at ve 3 yeni aksiyon kartı çek. Karşılaşılan panik kartlarını at.","f":"Sanırım daha önce buradaydım. Sanırım bir adım vardı."},"NO_BBQ":{"n":"MANGAL YOK!","d":"Hedef olduğun alev makinesi etkisini iptal et. 1 aksiyon kartı çek.","f":"Kıyafet 1200°C'ye dayanıyor. Bu şeye karşı — yaklaşık beş saniye."},"NO_THANKS":{"n":"HAYIR, TEŞEKKÜRLER!","d":"Kart değişimini reddet. 1 aksiyon kartı çek.","f":"Bardaktan bir filiz büyüyor. İçmiyorum."},"FEAR":{"n":"KORKU","d":"Değişimi reddet ve reddedilen karta bak. 1 aksiyon kartı çek.","f":"— Dave! Hava kilidini aç! — …Dave."},"CHAIN_REACTION":{"n":"ZİNCİR REAKSİYON","d":"Her oyuncu aynı anda karantina ve barikat kapıları görmezden gelerek bir sonraki oyuncuya 1 kart geçirir. Turun biter.","f":"Sinyal tüm iç iletişim kanallarından geçti. Kimse sessiz kalamaz."},"THREE_FOUR":{"n":"…ÜÇ, DÖRT…","d":"…kapıyı sonuna kadar açın! Tüm oynanan barikat kapıları atılır.","f":"Tahtalar üçüncü darbede kırılır. İkincisinde — artık insan olmayan bir şeyle vuruyorsanız."},"ONE_TWO":{"n":"BİR, İKİ…","d":"…O Şey derinliklerden yükseldi! Solunuzda veya sağınızda (seçiminize bağlı) üçüncü oyuncuyla yer değiştirin. Barikat kapıları görmezden gelin.","f":"Zemin ızgarasının altında bir şey var. Ve bugün altta olmaktan sıkıldığına karar verdi."},"JUST_BETWEEN_US":{"n":"ARAMIZDA KALSIN…","d":"Elindeki tüm kartları seçtiğin komşu oyuncuya göster.","f":"Şifreli kanal. Sadece onun duyacağını garanti eder. Ve ne olduğunu."},"LETS_BE_FRIENDS":{"n":"ARKADAŞ OLALIM!","d":"Karantinada olmayan herhangi bir oyuncuyla 1 kart değiştir.","f":"Eldiven sıcak. Çok sıcak. Ve içinde bir şey hareket ediyor."},"CONFESSION_TIME":{"n":"İTİRAF ZAMANI","d":"Senden başlayarak tur sırasına göre her oyuncu kartlarını diğerlerine gösterir ya da göstermez.","f":"Lamba altında herkes şüpheli. Işık bile."},"AXE":{"n":"BALTA","d":"Kendin veya komşundan karantinayı kaldır, ya da aranızdaki barikat kapıyı kaldır.","f":"Acil dolap camı oraya vardığımda zaten kırıktı."},"SWAP_PLACES":{"n":"YER DEĞİŞTİR!","d":"Karantinada olmayan komşu oyuncuyla yer değiştir. Tüm barikat kapıları görmezden gel.","f":"Koridor her iki taraftan aynı görünüyor. Ya da öyle mi?"},"QUARANTINE":{"n":"KARANTİNA","d":"Kendin veya komşu bir oyuncu için oyna. Sonraki 3 turda karantinaya alınan oyuncu kart değişimi yapamaz ve aksiyon kartı oynayamaz.","f":"Bağlandı. Tıkaca bağırmanın anlamı yok — kimse duymaz."},"SUSPICION":{"n":"ŞÜPHE","d":"Komşu oyuncunun elinden 1 rastgele karta bak.","f":"Otururken — solakti. O andan beri kupasını üç kez sağ eliyle kaldırdı."},"REVERSE":{"n":"BİRŞEY HAREKET EDİYOR","d":"Tur ve değişim yönünü tersine çevirir.","f":"Koridorun ilerisinde bir şey hareket ediyor. Yavaşça. Ama kesinlikle bize doğru."},"PERSISTENCE":{"n":"ISINMA","d":"3 aksiyon kartı çek, 1 tanesini tut ve diğer 2 tanesini at. Ardından 1 kart oyna veya at.","f":"Kan benim değil. Yani, hepsi değil."},"WHISKY":{"n":"VİSKİ","d":"Tüm kartlarını diğer oyunculara göster. Yalnızca kendin için oynanabilir.","f":"Sıfır yerçekiminde buz şakırdamaz. Ama bardak tam olması gereken yere doğru kayıyor."},"RUN_AWAY":{"n":"BURADAN KAÇIN!","d":"Karantinada olmayan herhangi bir oyuncuyla yer değiştir. Tüm barikat kapıları görmezden gel.","f":"Kaçış kapsülüne 90 metre. Onun 92 metresi var."},"NECRONOMICON":{"n":"GEMİ GÜNLÜĞÜ","d":"Herhangi bir oyuncuyu elersin.","f":"Günlük 16: «Kendi kendini imha başlatılıyor. Kedini sev.»"},"OOPS":{"n":"EYVAH!","d":"Elindeki tüm kartları diğer oyunculara göster.","f":"Eldiven kaygan. Kartlar yüzü kapalı düşüyor — ama bu yüzü açık indi."},"TEMPTATION":{"n":"AYARTMA","d":"Karantinada olmayan herhangi bir oyuncuyla 1 kart değiştir. Turun biter.","f":"Kapsül çekiyor. Sıcak gibi görünüyor. Nefes alıyor gibi görünüyor."},"FLAMETHROWER":{"n":"ALEV MAKİNESİ","d":"Komşu bir oyuncu oyundan elenir.","f":"Yanıma yaklaşan herkesi yakacağıma yemin ederim."},"BLIND_DATE":{"n":"KÖR RANDEVU","d":"Elinden 1 kartı deste ile değiştir, karşılaşılan panik kartlarını at.","f":"Makine rastgele bir kader veriyor. İade edilmez."},"OLD_ROPES":{"n":"ESKİ İPLER","d":"Bu işe yaramaz ipler en küçük dokunuşta kopuyor! Tüm karantinalar atılır.","f":"Aceleyle bağlandı. Ve aynı hızla bitti."},"LOVECRAFT":{"n":"BAŞ SUBAY","d":"Herhangi bir oyuncunun elindeki kartlara bak.","f":"En eski ve en güçlü korku, bilinmeyenden korkudur. Ve işte onun önünde duruyoruz."},"WHAT_A_PARTY":{"n":"NE PARTİ!","d":"Tüm karantinalar ve barikat kapılar atılır. Ardından senden başlayarak tüm oyuncular saat yönünde ikili olarak yer değiştirir.","f":"Stroboskop yanıp sönüyor. Biri dans ediyor. Biri neredeyse dans ediyor."}}},"zh-cn":{"title":"怪物","htmlTitle":"怪物 — 感染协议","metaDesc":"Jackbox 风格桌游的本地数字模拟器。主机运行在电视 / Android TV / 平板上，玩家用手机扫二维码加入。4–12 人，Wi-Fi，无需注册。","heroRec":"REC · 航行日志 · 会话开启","heroTag":"墙上一块屏，手机当手柄。趁飞船还在呼吸，<b>找出被感染的人</b>。","heroSub":"Jackbox 风格桌游的本地数字模拟器。八人船员，八条生物信号。外加一条本不该存在的。","vPlayTV":"平板 / 电视","vReg":"无需","ctaPlay":"Google Play · 平板 / 电视","ctaGameplay":"实机演示","ctaDeck":"卡组","s1k":"// 来自飞船的信号","s1h":"实战对局","s1sub":"一桌真实对局：共享屏幕上的笔记本或 Android 主机——以及玩家们的手机。","cap":"共享桌面——所有人都看得到。秘密留在手机里。","ytTag":"▶ 对局录像 · YOUTUBE","s2k":"// 回合协议","s2h":"回合阶段","s2sub":"每回合都有三个必经阶段。一个都跳不过——飞船不允许。","p1n":"阶段 1","p1h":"抽牌","p1p":"从牌堆顶抽一张牌。若抽到“恐慌”牌，立即结算。","p2n":"阶段 2","p2h":"出牌","p2p":"打出一张行动牌——或弃牌。防御牌不在此阶段打出，它们是反应。","p3n":"阶段 3","p3h":"交换","p3p":"把一张牌递给邻座。对方用防御挡下——或接受。落入手中的牌，永远留下。","shipNote":"<b>◆ 核心规则：</b>正是通过交换，<b>怪物</b>才传播感染。每名玩家都成为同谋、携带者或受害者——有时浑然不觉。","s3k":"// 分发","s3h":"下载主机端","s3sub":"主机就是“牌桌”。玩家无需安装：用手机扫二维码即可加入。","metaAndroid":"平板 / ANDROID TV","featBadge":"推荐","hostNote":"<b>Android 是主机端</b>，不是客户端。平板或 Android TV 盒子取代笔记本：运行同一套 Ktor 服务器，把共享牌桌投到大屏上。玩家依旧用手机经浏览器扫二维码加入——无需安装任何东西。","s4k":"// 船上军械库","s4h":"卡组","s4sub":"三种卡牌。行动牌在自己回合打出，防御牌回应他人，恐慌牌取代普通抽牌且立即生效。","tabAct":"行动 · 14","tabDef":"防御 · 5","tabPan":"恐慌 · 12","grpAct":"🟠 行动——在阶段 2 打出","grpDef":"🟢 防御——回应他人回合","grpPan":"🟣 恐慌——立即触发","tagAct":"行动","tagDefEx":"防御 · 交换","tagDefMove":"防御 · 移动","tagDefFlame":"防御 · 喷火器","tagPan":"恐慌","noteDef":"◆ 防御牌不在自己回合打出——仅作为反应。每张防御牌作为补偿，让你从牌堆<b>多抽 1 张</b>。","notePanic":"<b>⚠ 恐慌牌</b>从独立牌堆中取代普通抽牌抽出。立即结算——不能弃置、不能保留、不能预先防御。恐慌无视隔离，恐慌不识门户。","s5k":"// 行前简报","s5h":"怎么玩","step1":"主机方在<b>平板、Android TV、笔记本或 Steam Deck</b> 上启动应用——画面投到大屏。","step2":"玩家用手机扫描屏幕上的<b>二维码</b><i>（Chrome / Firefox）</i>。无需安装。","step3":"发牌、行动、交换——全<b>在手机上</b>。大屏是飞船的公共记忆，没有秘密。","reqH":"配置要求","reqHostH":"🖥️ 主机","reqHostP":"平板 / Android TV / 任意笔记本 / 带 Wi-Fi 的 Steam Deck","reqPlayersH":"📱 玩家","reqPlayersP":"装有 Chrome 或 Firefox 的手机（不支持 Safari）","reqNetH":"📡 网络","reqNetP":"共用 Wi-Fi——飞船无需联外网即可运行","footQuote":"「绿色的东西，可别递给我。」","lnkPrivacy":"隐私政策","bStatus":"状态","bPlayers":"玩家","bNet":"网络","bReg":"注册","bLic":"许可","sub":"感染协议","cards":{"MISS":{"n":"没打中！","d":"拒绝交换牌，由你之后的下一位玩家代替你交换。抽 1 张行动牌。","f":"——今天不行，亲爱的。也许下次吧。"},"GET_OUT":{"n":"滚出去！","d":"与任意选择的玩家（非隔离）交换位置。","f":"气闸3秒后启动。没有时间穿宇航服了。"},"BARRICADED_DOOR":{"n":"封堵的门","d":"将此牌放在你与相邻玩家之间。你们之间不能进行任何行动或交换。","f":"焊死的，钉死的，涂漆的。有人非常不想让它出去。"},"ANALYSIS":{"n":"分析","d":"查看所选相邻玩家手中的所有牌。","f":"……现在让我们看看你究竟是什么。"},"STAY_HERE":{"n":"我就待这儿！","d":"若你成为「换位置！」或「快跑！」的目标，取消其效果。抽 1 张行动牌。","f":"我有椅子。我有灯。我膝盖上有枪。我哪儿也不去。"},"FORGETFULNESS":{"n":"健忘","d":"弃掉手中 3 张牌，抽 3 张新的行动牌。遇到恐慌牌时弃置。","f":"我想我以前来过这里。我想我曾经有个名字。"},"NO_BBQ":{"n":"不烧烤！","d":"若你成为喷火器牌的目标，取消其效果。抽 1 张行动牌。","f":"这套宇航服能承受1200°C。但对这个东西——大约五秒。"},"NO_THANKS":{"n":"不了谢谢！","d":"拒绝交换牌。抽 1 张行动牌。","f":"杯子里长出了藤蔓。不喝了。"},"FEAR":{"n":"恐惧","d":"拒绝交换牌并查看被拒绝的牌。抽 1 张行动牌。","f":"——戴夫！打开气闸！——……戴夫。"},"CHAIN_REACTION":{"n":"连锁反应","d":"每位玩家同时向下一位玩家传递 1 张牌，无视所有隔离和封堵门牌。你的回合结束。","f":"信号同时传遍了所有内部通讯。没有人能保持沉默。"},"THREE_FOUR":{"n":"…三，四…","d":"…大开门！所有已出的封堵门牌被弃置。","f":"木板第三下就断了。第二下——如果你用的东西已经不再是人类。"},"ONE_TWO":{"n":"一，二…","d":"…怪物从深处升起！与你左边或右边第三位玩家交换位置（你选择）。无视所有封堵门。","f":"地板格栅下面有东西。今天它决定不再待在下面了。"},"JUST_BETWEEN_US":{"n":"只在我们之间…","d":"向你选择的相邻玩家展示你所有的手牌。","f":"加密频道。保证只有他能听到。还有那个变成他的东西。"},"LETS_BE_FRIENDS":{"n":"交个朋友？","d":"与任意选择的玩家（非隔离）交换 1 张牌。","f":"手套很温暖。太温暖了。里面有什么东西在动。"},"CONFESSION_TIME":{"n":"坦白时间","d":"从你开始按回合顺序，每位玩家选择向其他人展示或不展示自己的所有手牌。","f":"在灯光下，每个人都是嫌疑人。甚至连光也是。"},"AXE":{"n":"斧头","d":"解除自己或相邻玩家的隔离，或移除你们之间的封堵门。","f":"紧急柜的玻璃在我来之前就已经被打碎了。"},"SWAP_PLACES":{"n":"换位置！","d":"与相邻玩家（非隔离）交换位置。无视所有封堵门。","f":"走廊两端看起来一模一样。真的吗？"},"QUARANTINE":{"n":"隔离","d":"对自己或相邻玩家使用。接下来 3 个自己的回合内，被隔离的玩家不能交换牌、出行动牌，也不能成为此类牌的目标。","f":"被绑住了。对着堵嘴的东西喊叫毫无意义——没有人能听到。"},"SUSPICION":{"n":"怀疑","d":"查看相邻玩家手中的 1 张随机牌。","f":"坐下时，他是左撇子。从那以后，他用右手拿了三次杯子。"},"REVERSE":{"n":"有东西在移动","d":"改变回合和交换的方向。","f":"走廊更深处有东西在移动。很慢。但绝对朝着我们。"},"PERSISTENCE":{"n":"坚持","d":"抽 3 张行动牌，留 1 张在手中，弃掉另外 2 张。然后出牌或弃牌 1 张。","f":"血不是我的。至少不全是。"},"WHISKY":{"n":"威士忌","d":"向其他玩家展示你所有的牌。此牌只能对自己使用。","f":"在失重状态下冰块不会叮当作响。但杯子会漂向它该去的地方。"},"RUN_AWAY":{"n":"快跑！","d":"与任意选择的玩家（非隔离）交换位置。无视所有封堵门。","f":"逃生舱还有90米。它距离有92米。"},"NECRONOMICON":{"n":"航海日志","d":"淘汰任意选择的玩家。","f":"日志16：「启动自毁程序。好好照顾你的猫。」"},"OOPS":{"n":"哎呀！","d":"向其他玩家展示你所有的手牌。","f":"手套很滑。牌背面朝下掉落——但这一张正面朝上。"},"TEMPTATION":{"n":"诱惑","d":"与任意选择的玩家（非隔离）交换 1 张牌。你的回合结束。","f":"太空舱在招唤。感觉很温暖。感觉像在呼吸。"},"FLAMETHROWER":{"n":"喷火器","d":"淘汰一名相邻玩家。","f":"我发誓，任何靠近我的人都会被我烧掉。"},"BLIND_DATE":{"n":"相亲","d":"将手中 1 张牌与牌堆顶部的牌交换，弃置途中遇到的所有恐慌牌。","f":"机器发出随机命运。不可退换。"},"OLD_ROPES":{"n":"旧绳子","d":"这些没用的绳子轻轻一扯就断！所有已出的隔离牌被弃置。","f":"仓促绑好的。结果也仓促地结束了。"},"LOVECRAFT":{"n":"大副","d":"查看任意选择玩家手中的所有牌。","f":"最古老最强烈的恐惧是对未知的恐惧。而现在我们就站在它面前。"},"WHAT_A_PARTY":{"n":"这叫派对吗？","d":"所有已出的隔离和封堵门牌被弃置。然后从你开始顺时针，所有玩家两两交换位置。","f":"频闪灯在闪烁。有人在跳舞。有人……差不多在跳舞。"}}},"ja":{"title":"怪物","htmlTitle":"怪物 — 感染プロトコル","metaDesc":"Jackbox 風ボードゲームのローカル・デジタルシミュレーター。ホストは TV / Android TV / タブレットで動作し、プレイヤーはスマホの QR コードで参加。4〜12 人、Wi-Fi、登録不要。","heroRec":"REC · 航海日誌 · セッション開始","heroTag":"壁に一枚の画面、スマホはコントローラー。船がまだ息をしているうちに、<b>感染者を見つけ出せ</b>。","heroSub":"Jackbox 風ボードゲームのローカル・デジタルシミュレーター。乗員は八人。生体反応も八つ。そして、いるはずのないもう一つ。","vPlayTV":"タブレット / TV","vReg":"不要","ctaPlay":"Google Play · タブレット / TV","ctaGameplay":"ゲームプレイ","ctaDeck":"デッキ","s1k":"// 船からの信号","s1h":"実プレイ","s1sub":"ひとつの卓での本番対戦：共有画面のノートPCまたはAndroidホスト——そしてプレイヤーのスマホ。","cap":"共有テーブル——全員が見るもの。秘密はスマホの中に。","ytTag":"▶ 対戦の記録 · YOUTUBE","s2k":"// ターンの手順","s2h":"ターンのフェーズ","s2sub":"各ターンには必須の3フェーズ。ひとつも飛ばせない——船が許さない。","p1n":"フェーズ1","p1h":"カードを引く","p1p":"山札の一番上を引く。「パニック」カードなら即座に処理される。","p2n":"フェーズ2","p2h":"プレイ","p2p":"アクションカードを1枚プレイ——または捨てる。防御カードはここでは出さない、リアクションだ。","p3n":"フェーズ3","p3h":"交換","p3p":"隣のプレイヤーにカードを渡す。相手は防御で弾く——または受け取る。手に入ったものは残る。永遠に。","shipNote":"<b>◆ 最重要ルール：</b>まさに交換を通じて<b>怪物</b>は感染を広げる。プレイヤーは皆、共犯者・媒介者・犠牲者になる——時に自分でも気づかぬまま。","s3k":"// 配布","s3h":"ホストをダウンロード","s3sub":"ホストは「卓」だ。プレイヤーは何もインストールしない：スマホの QR コードで参加する。","metaAndroid":"タブレット / ANDROID TV","featBadge":"おすすめ","hostNote":"<b>Android はホスト</b>であってクライアントではない。タブレットや Android TV 端末がノートPCの代わりに、同じ Ktor サーバーを立ち上げ、共有卓を大画面に映す。プレイヤーは従来どおりスマホのブラウザと QR コードで参加——何もインストールしない。","s4k":"// 船内兵装","s4h":"デッキ","s4sub":"カードは3種類。アクションは自分の番に、防御は他人の番への反応、パニックは通常の引きの代わりに引かれ即発動する。","tabAct":"アクション · 14","tabDef":"防御 · 5","tabPan":"パニック · 12","grpAct":"🟠 アクション——フェーズ2でプレイ","grpDef":"🟢 防御——他人の番への反応","grpPan":"🟣 パニック——即座に発動","tagAct":"アクション","tagDefEx":"防御 · 交換","tagDefMove":"防御 · 移動","tagDefFlame":"防御 · 火炎放射器","tagPan":"パニック","noteDef":"◆ 防御は自分の番には出せない——リアクション専用。防御カードは補償として山札から<b>+1枚</b>引ける。","notePanic":"<b>⚠ パニック</b>は通常の引きの代わりに別の山から引かれる。即座に処理される——捨てる・温存する・前もって防ぐ、いずれも不可。パニックは隔離に従わず、扉も知らない。","s5k":"// ブリーフィング","s5h":"遊び方","step1":"ホストが<b>タブレット・Android TV・ノートPC・Steam Deck</b> でアプリを起動——画面を大画面へ。","step2":"プレイヤーは画面の<b>QR コード</b>をスマホで読み取る<i>（Chrome / Firefox）</i>。インストール不要。","step3":"配札・手番・交換——すべて<b>スマホで</b>。大画面は船の共有記憶、秘密はなし。","reqH":"動作環境","reqHostH":"🖥️ ホスト","reqHostP":"タブレット / Android TV / 任意のノートPC / Wi-Fi対応 Steam Deck","reqPlayersH":"📱 プレイヤー","reqPlayersP":"Chrome または Firefox のスマホ（Safari 非対応）","reqNetH":"📡 ネットワーク","reqNetP":"共有 Wi-Fi——船は外部接続なしで動く","footQuote":"「緑のものだけは、よこさないでくれ。」","lnkPrivacy":"プライバシー","bStatus":"ステータス","bPlayers":"プレイヤー","bNet":"ネット","bReg":"登録","bLic":"ライセンス","sub":"感染プロトコル","cards":{"MISS":{"n":"かわした!","d":"カード交換を断り、代わりに次のプレイヤーが交換します。アクションカードを1枚引きます。","f":"— 今日はダメです、あなた。また今度。"},"GET_OUT":{"n":"出て行け!","d":"隔離中でない任意のプレイヤーと場所を交換します。","f":"エアロックは3秒後に作動します。宇宙服を着る時間はありません。"},"BARRICADED_DOOR":{"n":"封鎖されたドア","d":"このカードを自分と隣接プレイヤーの間に置きます。その間ではいかなるアクションも交換も行えません。","f":"溶接され、釘付けられ、塗装されています。誰かがこれを出したくなかったのです。"},"ANALYSIS":{"n":"分析","d":"選んだ隣接プレイヤーの手札を全て確認します。","f":"…さあ、あなたが本当に誰なのか見てみましょう。"},"STAY_HERE":{"n":"ここにいる!","d":"「場所を変わって!」または「逃げろ!」の対象になった場合、その効果を取り消します。アクションカードを1枚引きます。","f":"椅子があります。ランプがあります。膝に銃があります。どこにも行きません。"},"FORGETFULNESS":{"n":"物忘れ","d":"手札から3枚捨て、新しいアクションカードを3枚引きます。パニックカードは捨てます。","f":"ここに来たことがある気がします。名前があった気がします。"},"NO_BBQ":{"n":"BBQはお断り!","d":"火炎放射器の対象になった場合、その効果を取り消します。アクションカードを1枚引きます。","f":"このスーツは1200°Cに耐えます。これに対しては — 約5秒。"},"NO_THANKS":{"n":"いいえ、結構!","d":"カード交換を断ります。アクションカードを1枚引きます。","f":"グラスからツタが生えています。飲みません。"},"FEAR":{"n":"恐怖","d":"カード交換を断り、断ったカードを確認します。アクションカードを1枚引きます。","f":"— デイブ！エアロックを開けて！— …デイブ。"},"CHAIN_REACTION":{"n":"連鎖反応","d":"全プレイヤーが同時にターン順に次のプレイヤーへカード1枚を渡します。全ての隔離と封鎖されたドアを無視します。あなたのターンが終了します。","f":"信号が全ての内部通信に同時に届きました。誰も沈黙を保てません。"},"THREE_FOUR":{"n":"…三、四…","d":"…ドアを大きく開けろ！全ての使用済み封鎖されたドアカードが捨て札になります。","f":"板は3回目の打撃で折れます。2回目は — もはや人間でないものが叩くときです。"},"ONE_TWO":{"n":"一、二…","d":"…怪物が深海から浮上した！左または右の3番目のプレイヤーと場所を交換します（選択可）。全ての封鎖されたドアを無視します。","f":"床の格子の下に何かいます。そして今日、それは下にいることに飽きたと決めました。"},"JUST_BETWEEN_US":{"n":"ここだけの話…","d":"選んだ隣接プレイヤーに全ての手札を見せます。","f":"暗号化チャンネル。彼だけが聞くことを保証します。そして彼になった何かも。"},"LETS_BE_FRIENDS":{"n":"友達になろう!","d":"隔離中でない任意のプレイヤーとカード1枚を交換します。","f":"手袋が温かいです。温かすぎます。中で何かが動いています。"},"CONFESSION_TIME":{"n":"告白の時間","d":"あなたから始めてターン順に、各プレイヤーが全ての手札を他のプレイヤーに見せるか見せないかを選びます。","f":"ランプの下では全員が容疑者です。光でさえも。"},"AXE":{"n":"斧","d":"自分または隣接プレイヤーの隔離を解除するか、あなたとの間の封鎖されたドアを取り除きます。","f":"緊急キャビネットのガラスは、私が来たときにはすでに割れていました。"},"SWAP_PLACES":{"n":"場所を変わって!","d":"隔離中でない隣接プレイヤーと場所を交換します。全ての封鎖されたドアを無視します。","f":"廊下は両端から見ても同じように見えます。本当に？"},"QUARANTINE":{"n":"隔離","d":"自分または隣接プレイヤーに使います。次の3ターン間、隔離されたプレイヤーはカードを交換したり、アクションカードを出したり、そのようなカードの対象になったりできません。","f":"縛られています。猿轡に向かって叫んでも無駄です — 誰も聞こえません。"},"SUSPICION":{"n":"疑惑","d":"隣接プレイヤーの手札からランダムに1枚確認します。","f":"座ったとき、彼は左利きでした。それ以来、右手でマグカップを3回持ちました。"},"REVERSE":{"n":"何かが動いている","d":"ターンと交換の方向を逆にします。","f":"廊下の先で何かが動いています。ゆっくりと。でも確実に私たちの方へ。"},"PERSISTENCE":{"n":"粘り強さ","d":"アクションカードを3枚引き、1枚を手札に残して残りの2枚を捨てます。その後カード1枚を出すか捨てます。","f":"この血は私のものではありません。まあ、全部ではありませんが。"},"WHISKY":{"n":"ウイスキー","d":"全ての手札を他のプレイヤーに見せます。このカードは自分にしか使えません。","f":"無重力では氷がチリンと鳴りません。でもグラスはちょうど必要なところへ漂っていきます。"},"RUN_AWAY":{"n":"逃げろ!","d":"隔離中でない任意のプレイヤーと場所を交換します。全ての封鎖されたドアを無視します。","f":"脱出ポッドまで90メートル。それは92メートルのところにいます。"},"NECRONOMICON":{"n":"航海日誌","d":"任意のプレイヤーを脱落させます。","f":"記録16：「自己破壊シーケンスを開始します。猫を大切に。」"},"OOPS":{"n":"しまった!","d":"全ての手札を他のプレイヤーに見せます。","f":"手袋が滑っています。カードは裏面を上にして落ちます — でもこれだけ表面が上になりました。"},"TEMPTATION":{"n":"誘惑","d":"隔離中でない任意のプレイヤーとカード1枚を交換します。あなたのターンが終了します。","f":"カプセルが手招きしています。暖かそうです。呼吸しているようです。"},"FLAMETHROWER":{"n":"火炎放射器","d":"隣接するプレイヤーをゲームから脱落させます。","f":"近づく者は誰でも焼き尽くすと誓います。"},"BLIND_DATE":{"n":"ブラインドデート","d":"手札から1枚をデッキの一番上のカードと交換します。途中のパニックカードは捨てます。","f":"機械がランダムな運命を吐き出します。返品不可。"},"OLD_ROPES":{"n":"古いロープ","d":"このくだらないロープはちょっと触れるだけで切れます！全ての使用済み隔離カードが捨て札になります。","f":"急いで縛りました。同じくらい急いで終わりました。"},"LOVECRAFT":{"n":"航海士","d":"選んだ任意のプレイヤーの手札を全て確認します。","f":"最も古く最も強い恐怖は未知への恐怖です。そして今私たちはその前に立っています。"},"WHAT_A_PARTY":{"n":"これがパーティ？","d":"全ての使用済み隔離および封鎖されたドアカードが捨て札になります。その後、あなたから時計回りに全プレイヤーがペアで場所を交換します。","f":"ストロボが点滅しています。誰かが踊っています。誰かはほぼ踊っています。"}}},"ko":{"title":"괴물","htmlTitle":"괴물 — 감염 프로토콜","metaDesc":"Jackbox 스타일 보드게임의 로컬 디지털 시뮬레이터. 호스트는 TV / Android TV / 태블릿에서 실행되고, 플레이어는 휴대폰 QR 코드로 참여합니다. 4–12명, Wi-Fi, 가입 불필요.","heroRec":"REC · 항해 일지 · 세션 열림","heroTag":"벽엔 화면 하나, 폰은 컨트롤러. 배가 아직 숨 쉴 때 <b>감염자를 찾아내라</b>.","heroSub":"Jackbox 스타일 보드게임의 로컬 디지털 시뮬레이터. 여덟 명의 승무원. 여덟 개의 생체 신호. 그리고 있어선 안 될 하나가 더.","vPlayTV":"태블릿 / TV","vReg":"불필요","ctaPlay":"Google Play · 태블릿 / TV","ctaGameplay":"게임플레이","ctaDeck":"덱","s1k":"// 함선에서 온 신호","s1h":"실전 플레이","s1sub":"한 테이블의 실제 대국: 공유 화면의 노트북 또는 Android 호스트 — 그리고 플레이어들의 폰.","cap":"공유 테이블 — 모두가 보는 것. 비밀은 폰에 남는다.","ytTag":"▶ 대국 기록 · YOUTUBE","s2k":"// 턴 프로토콜","s2h":"턴 단계","s2sub":"매 턴마다 세 개의 필수 단계가 있다. 하나도 건너뛸 수 없다 — 배가 허락하지 않는다.","p1n":"단계 1","p1h":"카드를 뽑는다","p1p":"덱 맨 위 카드를 가져온다. ‘패닉’ 카드라면 즉시 발동된다.","p2n":"단계 2","p2h":"플레이한다","p2p":"행동 카드 한 장을 낸다 — 또는 버린다. 방어 카드는 여기서 내지 않는다, 반응이다.","p3n":"단계 3","p3h":"교환한다","p3p":"이웃에게 카드를 건넨다. 상대는 방어로 막거나 — 받아들인다. 손에 들어온 것은 남는다. 영원히.","shipNote":"<b>◆ 핵심 규칙:</b> 바로 교환을 통해 <b>괴물</b>이 감염을 퍼뜨린다. 모든 플레이어는 공범, 매개자 또는 희생자가 된다 — 때로는 자신도 모르게.","s3k":"// 배포","s3h":"호스트 다운로드","s3sub":"호스트는 ‘테이블’이다. 플레이어는 아무것도 설치하지 않는다: 폰의 QR 코드로 참여한다.","metaAndroid":"태블릿 / ANDROID TV","featBadge":"추천","hostNote":"<b>Android는 호스트</b>이지 클라이언트가 아니다. 태블릿이나 Android TV 기기가 노트북을 대신해 같은 Ktor 서버를 띄우고 공유 테이블을 큰 화면에 띄운다. 플레이어는 여전히 폰의 브라우저와 QR 코드로 참여한다 — 아무것도 설치하지 않는다.","s4k":"// 함내 무기고","s4h":"덱","s4sub":"카드는 세 종류. 행동은 자기 턴에, 방어는 남의 턴에 대한 반응, 패닉은 일반 드로 대신 뽑혀 즉시 발동한다.","tabAct":"행동 · 14","tabDef":"방어 · 5","tabPan":"패닉 · 12","grpAct":"🟠 행동 — 2단계에 플레이","grpDef":"🟢 방어 — 남의 턴에 대한 반응","grpPan":"🟣 패닉 — 즉시 발동","tagAct":"행동","tagDefEx":"방어 · 교환","tagDefMove":"방어 · 이동","tagDefFlame":"방어 · 화염방사기","tagPan":"패닉","noteDef":"◆ 방어는 자기 턴에 내지 않는다 — 오직 반응으로만. 방어 카드는 보상으로 덱에서 <b>+1장</b>을 준다.","notePanic":"<b>⚠ 패닉</b>은 일반 카드 대신 별도 덱에서 뽑힌다. 즉시 발동된다 — 버리거나, 쥐고 있거나, 미리 방어할 수 없다. 패닉은 격리를 따르지 않고, 문도 모른다.","s5k":"// 브리핑","s5h":"플레이 방법","step1":"호스트가 <b>태블릿, Android TV, 노트북 또는 Steam Deck</b> 에서 앱을 실행 — 화면을 큰 디스플레이로 보낸다.","step2":"플레이어는 화면의 <b>QR 코드</b>를 폰으로 스캔한다 <i>(Chrome / Firefox)</i>. 설치 불필요.","step3":"분배, 턴, 교환 — 모두 <b>폰에서</b>. 큰 화면은 배의 공유 기억, 비밀은 없다.","reqH":"요구 사항","reqHostH":"🖥️ 호스트","reqHostP":"태블릿 / Android TV / 아무 노트북 / Wi-Fi 되는 Steam Deck","reqPlayersH":"📱 플레이어","reqPlayersP":"Chrome 또는 Firefox가 있는 폰 (Safari 미지원)","reqNetH":"📡 네트워크","reqNetP":"공용 Wi-Fi — 배는 외부 연결 없이 작동한다","footQuote":"「초록색인 건, 나한테 건네지 마.」","lnkPrivacy":"개인정보","bStatus":"상태","bPlayers":"플레이어","bNet":"네트워크","bReg":"가입","bLic":"라이선스","sub":"감염 프로토콜","cards":{"MISS":{"n":"빗나갔다!","d":"카드 교환을 거부하고 다음 플레이어가 대신 교환합니다. 행동 카드 1장을 뽑습니다.","f":"— 오늘은 안 돼요, 자기야. 다음에 또요."},"GET_OUT":{"n":"꺼져!","d":"격리 중이 아닌 임의의 플레이어와 자리를 바꿉니다.","f":"에어록이 3초 후 작동합니다. 우주복을 입을 시간이 없습니다."},"BARRICADED_DOOR":{"n":"봉쇄된 문","d":"이 카드를 자신과 인접 플레이어 사이에 놓습니다. 그 사이에서는 어떠한 행동이나 교환도 불가능합니다.","f":"용접되고, 못 박히고, 칠해졌습니다. 누군가 이것이 나오길 정말 원하지 않았습니다."},"ANALYSIS":{"n":"분석","d":"선택한 인접 플레이어의 모든 패를 확인합니다.","f":"…이제 당신이 진짜 누구인지 봅시다."},"STAY_HERE":{"n":"여기 있을래!","d":"「자리 바꿔!」 또는 「도망쳐!」의 대상이 되면 효과를 취소합니다. 행동 카드 1장을 뽑습니다.","f":"의자가 있습니다. 램프가 있습니다. 무릎 위에 총이 있습니다. 저는 어디도 안 갑니다."},"FORGETFULNESS":{"n":"건망증","d":"패에서 카드 3장을 버리고 새 행동 카드 3장을 뽑습니다. 패닉 카드는 버립니다.","f":"여기 온 적이 있는 것 같습니다. 이름이 있었던 것 같습니다."},"NO_BBQ":{"n":"바비큐는 싫어!","d":"화염방사기의 대상이 되면 효과를 취소합니다. 행동 카드 1장을 뽑습니다.","f":"이 우주복은 1200°C까지 버팁니다. 이 것에 대해서는 — 약 5초."},"NO_THANKS":{"n":"아니, 됐어!","d":"카드 교환을 거부합니다. 행동 카드 1장을 뽑습니다.","f":"잔에서 덩굴이 자라고 있습니다. 마시지 않겠습니다."},"FEAR":{"n":"공포","d":"카드 교환을 거부하고 거부한 카드를 확인합니다. 행동 카드 1장을 뽑습니다.","f":"— 데이브! 에어록 열어! — …데이브."},"CHAIN_REACTION":{"n":"연쇄 반응","d":"모든 플레이어가 동시에 턴 순서대로 다음 플레이어에게 카드 1장을 전달합니다. 격리 및 봉쇄된 문을 무시합니다. 턴이 종료됩니다.","f":"신호가 모든 내부 통신에 동시에 전달되었습니다. 아무도 침묵을 유지할 수 없습니다."},"THREE_FOUR":{"n":"…셋, 넷…","d":"…문을 활짝 열어라! 사용된 봉쇄된 문 카드를 모두 버립니다.","f":"판자는 세 번째 타격에 부러집니다. 두 번째에는 — 더 이상 인간이 아닌 것으로 칠 때."},"ONE_TWO":{"n":"하나, 둘…","d":"…괴물이 심해에서 올라왔다! 왼쪽 또는 오른쪽 세 번째 플레이어와 자리를 바꿉니다. 봉쇄된 문을 무시합니다.","f":"바닥 격자 아래에 무언가 있습니다. 그리고 오늘 그것은 아래에 있는 게 지쳤다고 결정했습니다."},"JUST_BETWEEN_US":{"n":"우리끼리 얘기인데…","d":"선택한 인접 플레이어에게 모든 패를 공개합니다.","f":"암호화된 채널. 그만이 들을 것이라고 보장합니다. 그리고 그가 된 무언가도."},"LETS_BE_FRIENDS":{"n":"친구 하자!","d":"격리 중이 아닌 임의의 플레이어와 카드 1장을 교환합니다.","f":"장갑이 따뜻합니다. 너무 따뜻합니다. 그 안에서 무언가 움직이고 있습니다."},"CONFESSION_TIME":{"n":"고백 시간","d":"당신부터 시작해 턴 순서대로 각 플레이어가 모든 패를 공개하거나 숨깁니다.","f":"조명 아래서 모두가 용의자입니다. 빛조차도."},"AXE":{"n":"도끼","d":"자신이나 인접 플레이어의 격리를 해제하거나, 사이의 봉쇄된 문을 제거합니다.","f":"비상 캐비닛 유리는 제가 왔을 때 이미 깨져 있었습니다."},"SWAP_PLACES":{"n":"자리 바꿔!","d":"격리 중이 아닌 인접 플레이어와 자리를 바꿉니다. 모든 봉쇄된 문을 무시합니다.","f":"복도는 양쪽 끝이 똑같아 보입니다. 정말로요?"},"QUARANTINE":{"n":"격리","d":"자신이나 인접 플레이어에게 사용합니다. 다음 3턴 동안 격리된 플레이어는 카드를 교환하거나, 행동 카드를 내거나, 그런 카드의 대상이 될 수 없습니다.","f":"묶여 있습니다. 재갈에 대고 소리치는 건 소용없어요 — 아무도 못 듣습니다."},"SUSPICION":{"n":"의심","d":"인접 플레이어의 패 중 무작위로 1장을 확인합니다.","f":"앉았을 때 그는 왼손잡이였습니다. 그 이후로 오른손으로 세 번 컵을 집었습니다."},"REVERSE":{"n":"무언가 움직이고 있어","d":"턴과 교환의 방향을 반대로 바꿉니다.","f":"복도 더 깊은 곳에서 무언가 움직이고 있습니다. 천천히. 하지만 분명히 우리 쪽으로."},"PERSISTENCE":{"n":"끈기","d":"행동 카드 3장을 뽑아 1장은 패에 남기고 나머지 2장은 버립니다. 그 후 카드 1장을 내거나 버립니다.","f":"피는 제 것이 아닙니다. 뭐, 전부는 아니지만."},"WHISKY":{"n":"위스키","d":"모든 패를 다른 플레이어에게 공개합니다. 이 카드는 자신에게만 사용할 수 있습니다.","f":"무중력에서는 얼음이 딸랑거리지 않습니다. 하지만 잔은 정확히 필요한 곳으로 떠갑니다."},"RUN_AWAY":{"n":"도망쳐!","d":"격리 중이 아닌 임의의 플레이어와 자리를 바꿉니다. 모든 봉쇄된 문을 무시합니다.","f":"탈출 포드까지 90미터. 그것은 92미터입니다."},"NECRONOMICON":{"n":"항해 일지","d":"임의의 플레이어를 탈락시킵니다.","f":"기록 16: 「자폭 시퀀스를 시작합니다. 고양이를 사랑하세요.」"},"OOPS":{"n":"이런!","d":"모든 패를 다른 플레이어에게 공개합니다.","f":"장갑이 미끄럽습니다. 카드가 뒷면으로 떨어집니다 — 하지만 이것만 앞면이 위로."},"TEMPTATION":{"n":"유혹","d":"격리 중이 아닌 임의의 플레이어와 카드 1장을 교환합니다. 턴이 종료됩니다.","f":"캡슐이 손짓합니다. 따뜻한 것 같습니다. 숨쉬는 것 같습니다."},"FLAMETHROWER":{"n":"화염방사기","d":"인접한 플레이어를 게임에서 탈락시킵니다.","f":"가까이 오는 사람은 누구든 태워버리겠다고 맹세합니다."},"BLIND_DATE":{"n":"블라인드 데이트","d":"패에서 카드 1장을 덱 상단 카드와 교환합니다. 패닉 카드는 버립니다.","f":"기계가 무작위 운명을 내놓습니다. 환불 불가."},"OLD_ROPES":{"n":"낡은 밧줄","d":"쓸모없는 밧줄은 살짝 건드리면 끊어집니다! 사용된 격리 카드를 모두 버립니다.","f":"서둘러 묶었습니다. 그리고 서둘러 끝났습니다."},"LOVECRAFT":{"n":"항해사","d":"선택한 임의의 플레이어 패를 모두 확인합니다.","f":"가장 오래되고 강한 공포는 미지에 대한 공포입니다. 그리고 지금 우리가 그것 앞에 서 있습니다."},"WHAT_A_PARTY":{"n":"이게 파티야?","d":"사용된 격리 및 봉쇄된 문 카드를 모두 버립니다. 그 후 당신부터 시계 방향으로 모든 플레이어가 쌍으로 자리를 바꿉니다.","f":"스트로브가 번쩍입니다. 누군가 춤추고 있습니다. 누군가는 거의 춤추고 있습니다."}}}};
